//  COVERS & TIME ZONES TAB
// ═══════════════════════════════════════════════════════════════
function renderCovers() {
  const d = getFiltered(); if(!d.length) return;
  const yrs = getActiveYears();

  const tRG = d.reduce((a,r)=>a+r.rest_gross,0);
  const tRN = d.reduce((a,r)=>a+r.rest_net,0);
  const tP  = d.reduce((a,r)=>a+r.ppl_rest_total,0);
  // Hotel breakfast: imported records use bfast_gross, manual records use hotel_bfast_gross
  const tBfG= d.reduce((a,r)=>a+(r.hotel_bfast_gross||r.bfast_gross||0),0);
  const tBfN= d.reduce((a,r)=>a+(r.hotel_bfast_net||r.bfast_net||0),0);
  const asp = tP ? tRN/tP : 0;

  $('cov-kpis').innerHTML = [
    kpiHtml('Restaurant Covers',fmtN(tP),'#7c5cfc',Math.round(tP/(d.length||1))+' avg per day'),
    kpiHtml('Avg Spend / Cover',fmt(asp),'#f5c842','net restaurant per guest'),
    kpiHtml('Restaurant Net',fmt(tRN),'#00d4aa','excl hotel breakfast'),
    kpiHtml('Hotel Breakfast',fmt(tBfN),'#ff6b35','tracked separately'),
  ].join('');

  // Covers by time zone totals
  const zones=[
    {k:'ppl_bfast',l:'Breakfast',c:'#f5c842'},
    {k:'ppl_lunch',l:'Lunch',c:'#00d4aa'},
    {k:'ppl_afternoon',l:'Afternoon',c:'#7c5cfc'},
    {k:'ppl_event',l:'Event',c:'#ff9f43'},
    {k:'ppl_dinner',l:'Dinner',c:'#ff6b35'},
    {k:'ppl_bar',l:'Bar',c:'#ff4466'},
  ];
  renderBars('cov-zone-bars', zones.map(z=>({l:z.l,v:d.reduce((a,r)=>a+(r[z.k]||0),0),c:z.c})).filter(x=>x.v>0));
  // Also show total restaurant covers
  

  // Covers by time zone by year
  mkChart('ch-cov-zones-year',{
    type:'bar',
    data:{
      labels:zones.map(z=>z.l),
      datasets:yrs.map(y=>({
        label:String(y),
        data:zones.map(z=>{const r=records.filter(x=>x.year==y&&x.gross>0);return r.reduce((a,x)=>a+(x[z.k]||0),0)||null;}),
        backgroundColor:YEAR_COLORS[y]+'cc',borderRadius:4,borderSkipped:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555'}}}}
  });

  // Avg covers by weekday
  renderBars('cov-dow-bars', DOW.map(day=>{
    const rows=d.filter(r=>r.day===day);
    const avg=rows.length?rows.reduce((a,r)=>a+r.ppl_rest_total,0)/rows.length:0;
    return {l:day.slice(0,3),v:avg,d:Math.round(avg).toString(),c:'#7c5cfc'};
  }));

  // Avg spend per cover by time zone
  const avgZones=[
    {k:'avg_lunch',l:'Lunch',c:'#00d4aa'},
    {k:'avg_afternoon',l:'Afternoon',c:'#7c5cfc'},
    {k:'avg_event',l:'Event',c:'#ff9f43'},
    {k:'avg_dinner',l:'Dinner',c:'#ff6b35'},
    {k:'avg_bar',l:'Bar',c:'#ff4466'},
    {k:'avg_total',l:'Total Avg',c:'#f5c842'},
  ];
  renderBars('cov-avg-spend-bars', avgZones.map(z=>{
    const rows=d.filter(r=>r[z.k]&&r[z.k]>0);
    const avg=rows.length?rows.reduce((a,r)=>a+r[z.k],0)/rows.length:0;
    return {l:z.l,v:avg,d:avg?fmt(avg):'—',c:z.c};
  }).filter(x=>x.v>0));

  // Avg spend per cover by year
  mkChart('ch-cov-asp-year',{
    type:'line',
    data:{
      labels:yrs.map(String),
      datasets:[{
        label:'Avg €/Cover',
        data:yrs.map(y=>{
          const r=records.filter(x=>x.year==y&&x.gross>0);
          const tN2=r.reduce((a,x)=>a+x.rest_net,0);
          const tP2=r.reduce((a,x)=>a+x.ppl_rest_total,0);
          return tP2?+(tN2/tP2).toFixed(2):0;
        }),
        borderColor:'#f5c842',backgroundColor:'rgba(245,200,66,.1)',
        borderWidth:3,pointRadius:6,pointBackgroundColor:'#f5c842',tension:.3,fill:true,
      }]
    },
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v)}}}}
  });

  // ── DISCOUNTS & COMPLIMENTARY ──────────────────────────────
  const totDisc=d.reduce((a,r)=>a+r.discounts_amt,0);
  const totComp=d.reduce((a,r)=>a+r.complimentary_amt,0);

  $('disc-kpis').innerHTML=[
    kpiHtml('Total Discounts',fmt(totDisc),'#ff4466',tRN?(totDisc/tRN*100).toFixed(1)+'% of net':'—'),
    kpiHtml('Total Complimentary',fmt(totComp),'#ff9f43',tRN?(totComp/tRN*100).toFixed(1)+'% of net':'—'),
    kpiHtml('Combined Impact',fmt(totDisc+totComp),'#ff6b35','total value given away'),
    kpiHtml('Adj Net Revenue',fmt(tRN-totDisc-totComp),'#00d4aa','after all deductions'),
  ].join('');

  const months=getActiveMonths();
  renderBars('disc-month-bars',months.map(m=>{
    const rows=d.filter(r=>r.month===m);
    return {l:m.slice(0,3),v:rows.reduce((a,r)=>a+r.discounts_amt,0),c:'#ff4466'};
  }).filter(x=>x.v>0));

  renderBars('comp-month-bars',months.map(m=>{
    const rows=d.filter(r=>r.month===m);
    return {l:m.slice(0,3),v:rows.reduce((a,r)=>a+r.complimentary_amt,0),c:'#ff9f43'};
  }).filter(x=>x.v>0));

  // Discounts & Comp by year
  mkChart('ch-disc-year',{
    type:'bar',
    data:{
      labels:yrs.map(String),
      datasets:[
        {label:'Discounts',data:yrs.map(y=>records.filter(x=>x.year==y).reduce((a,x)=>a+x.discounts_amt,0)),backgroundColor:'rgba(255,68,102,.7)',borderRadius:4,borderSkipped:false},
        {label:'Complimentary',data:yrs.map(y=>records.filter(x=>x.year==y).reduce((a,x)=>a+x.complimentary_amt,0)),backgroundColor:'rgba(255,159,67,.7)',borderRadius:4,borderSkipped:false},
      ]
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v/1000)+'k'}}}}
  });

  // ── HOTEL BREAKFAST ────────────────────────────────────────
  $('hb-info').innerHTML=`
    <div class="grid4" style="margin-top:0">
      ${kpiHtml('Hotel Bfast Gross',fmt(tBfG),'#f5c842','total hotel breakfast revenue')}
      ${kpiHtml('Hotel Bfast Net',fmt(tBfN),'#f5c842','hotel breakfast net')}
      ${kpiHtml('Restaurant Gross',fmt(tRG),'#00d4aa','excl hotel breakfast')}
      ${kpiHtml('Restaurant Net',fmt(tRN),'#00d4aa','excl hotel breakfast')}
    </div>
    <div style="margin-top:10px;font-family:monospace;font-size:11px;color:#666;padding:10px 14px;background:rgba(255,255,255,.03);border-radius:6px;line-height:1.6">
      📌 <strong>Hotel Breakfast is tracked separately</strong> and excluded from restaurant covers, avg spend, and P&L calculations.<br>
      The "Total Gross" in Overview includes hotel breakfast for complete turnover. Use "Restaurant" figures for F&amp;B performance.
    </div>`;
}




// ═══════════════════════════════════════════════════════════════
//  REPORTS TAB — from blue/red Excel sheets
// ═══════════════════════════════════════════════════════════════
const MONTHS_LABELS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const MONTHS_SHORT  = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const REPORT_YEAR_COLORS = {'2023':'#7c5cfc','2024':'#f5c842','2025':'#00d4aa','2026':'#ff6b35'};
const DAYS_LABELS = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday'];

let reportSection = 'monthly';


window.generateFlashReport = function() {
  const doc = new jsPDF({ orientation:'portrait', unit:'mm', format:'a4' });
  const W = 210; const M = 15;
  let y = M;

  // Get data for selected period
  const d = getFiltered();
  if(!d.length){ toast('No data for current filter','error'); return; }
  const selYear = yearFilter==='ALL'?'All Years':String(yearFilter);
  const selMonth = monthFilter==='ALL'?'All Months':monthFilter;

  const tG   = d.reduce((a,r)=>a+r.gross_total,0);
  const tN   = d.reduce((a,r)=>a+r.net_total,0);
  const tCov = d.reduce((a,r)=>a+r.ppl_rest_total,0);
  const tDisc= d.reduce((a,r)=>a+r.discounts_amt,0);
  const tComp= d.reduce((a,r)=>a+r.complimentary_amt,0);
  const tLu  = d.reduce((a,r)=>a+r.lunch_gross+(r.event_lunch_gross||0),0);
  const tAf  = d.reduce((a,r)=>a+r.afternoon_gross+(r.event_afternoon_gross||0),0);
  const tDn  = d.reduce((a,r)=>a+r.dinner_gross+(r.event_dinner_gross||0),0);
  const tBr  = d.reduce((a,r)=>a+r.bar_gross+(r.bar_event_gross||0),0);
  const tBf  = d.reduce((a,r)=>a+r.bfast_gross,0);
  const asp  = tCov ? tN/tCov : 0;
  const margin = tG ? (tN/tG*100) : 0;

  const costs = loadCosts(); const budgets = loadBudgets();
  const selYearK = yearFilter==='ALL'?'2026':String(yearFilter);
  const bud = budgets[selYearK]||{};
  const totalBudNet = Object.values(bud).reduce((a,m)=>a+(m.net||0),0);

  // Header
  doc.setFillColor(26,26,46);
  doc.rect(0,0,W,38,'F');
  doc.setTextColor(255,107,53);
  doc.setFontSize(22); doc.setFont('helvetica','bold');
  doc.text('RESTAURANT INTELLIGENCE', M, 16);
  doc.setFontSize(11); doc.setFont('helvetica','normal');
  doc.setTextColor(200,200,200);
  doc.text('Daily Flash Report', M, 24);
  doc.setTextColor(150,150,150);
  doc.setFontSize(9);
  doc.text(`Period: ${selMonth} ${selYear}   |   Generated: ${new Date().toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'})}   |   ${d.length} days`, M, 32);

  y = 46;

  // Section helper
  function sectionTitle(title) {
    doc.setFillColor(240,240,245);
    doc.rect(M-2, y-5, W-M*2+4, 8, 'F');
    doc.setTextColor(26,26,46); doc.setFontSize(9); doc.setFont('helvetica','bold');
    doc.text(title.toUpperCase(), M, y);
    y += 8; doc.setTextColor(50,50,50); doc.setFont('helvetica','normal');
  }

  function kpiRow(items) {
    const colW = (W - M*2) / items.length;
    items.forEach((item, i) => {
      const x = M + i*colW;
      doc.setFillColor(248,249,250);
      doc.roundedRect(x, y-2, colW-3, 18, 2, 2, 'F');
      doc.setFontSize(7); doc.setTextColor(120,120,120); doc.setFont('helvetica','normal');
      doc.text(item.label.toUpperCase(), x+4, y+4);
      doc.setFontSize(14); doc.setTextColor(30,30,30); doc.setFont('helvetica','bold');
      doc.text(item.value, x+4, y+13);
      if(item.sub) {
        doc.setFontSize(7); doc.setFont('helvetica','normal');
        doc.setTextColor(item.subColor||120,item.subColor?40:120,item.subColor?40:120);
        doc.text(item.sub, x+4, y+18);
      }
    });
    y += 24;
  }

  // Revenue KPIs
  sectionTitle('Revenue Summary');
  kpiRow([
    {label:'Total Gross Revenue', value:`€${Math.round(tG).toLocaleString()}`},
    {label:'Total Net Revenue',   value:`€${Math.round(tN).toLocaleString()}`, sub:`${margin.toFixed(1)}% margin`},
    {label:'vs Annual Budget',    value: totalBudNet ? (tN>=totalBudNet?'+':'')+((tN/totalBudNet-1)*100).toFixed(1)+'%' : 'No budget', sub: totalBudNet?`Budget: €${Math.round(totalBudNet).toLocaleString()}`:'Set budget in app', subColor: tN>=totalBudNet?0:200},
    {label:'Avg per Day',         value:`€${Math.round(tN/d.length).toLocaleString()}`, sub:`${d.length} days tracked`},
  ]);

  // Covers & Spend
  sectionTitle('Covers & Spend');
  kpiRow([
    {label:'Total Covers',       value: Math.round(tCov).toLocaleString()},
    {label:'Avg Covers/Day',     value: Math.round(tCov/d.length).toLocaleString()},
    {label:'Avg Spend/Cover',    value:`€${asp.toFixed(2)}`},
    {label:'Discounts & Comp',   value:`€${Math.round(tDisc+tComp).toLocaleString()}`, sub:`${tG?((tDisc+tComp)/tG*100).toFixed(1):'0'}% of gross`},
  ]);

  // Segment breakdown
  sectionTitle('Revenue by Time Zone');
  const segments = [
    {name:'Breakfast', val:tBf}, {name:'Lunch', val:tLu},
    {name:'Afternoon', val:tAf}, {name:'Dinner', val:tDn}, {name:'Bar', val:tBr},
  ].filter(s=>s.val>0);
  const segW = (W-M*2)/segments.length;
  segments.forEach((s,i) => {
    const x=M+i*segW;
    const pct = tG ? s.val/tG*100 : 0;
    doc.setFillColor(248,249,250);
    doc.roundedRect(x,y-2,segW-3,18,2,2,'F');
    doc.setFontSize(7); doc.setTextColor(120,120,120); doc.setFont('helvetica','normal');
    doc.text(s.name.toUpperCase(), x+4, y+4);
    doc.setFontSize(11); doc.setTextColor(30,30,30); doc.setFont('helvetica','bold');
    doc.text(`€${Math.round(s.val/1000).toLocaleString()}k`, x+4, y+12);
    doc.setFontSize(8); doc.setFont('helvetica','normal'); doc.setTextColor(80,80,80);
    doc.text(`${pct.toFixed(1)}%`, x+4, y+18);
    // Mini bar
    doc.setFillColor(220,220,230);
    doc.rect(x+4, y+20, segW-10, 2, 'F');
    doc.setFillColor(255,107,53);
    doc.rect(x+4, y+20, (segW-10)*pct/100, 2, 'F');
  });
  y += 28;

  // Top days
  sectionTitle('Top 5 Revenue Days');
  const topDays = [...d].sort((a,b)=>b.gross_total-a.gross_total).slice(0,5);
  doc.setFontSize(8); doc.setFont('helvetica','normal');
  const tdCols=[M,M+32,M+65,M+95,M+125,M+155];
  doc.setTextColor(120,120,120);
  ['Date','Day','Gross','Net','Covers','Avg/Cover'].forEach((h,i)=>doc.text(h.toUpperCase(),tdCols[i],y));
  y+=5; doc.setTextColor(50,50,50);
  topDays.forEach((r,idx) => {
    if(y>260){doc.addPage();y=20;}
    doc.setFillColor(idx%2===0?248:255,idx%2===0?249:255,idx%2===0?250:255);
    doc.rect(M-2,y-3,W-M*2+4,8,'F');
    doc.text(r.date, tdCols[0], y+2);
    doc.text(r.day?.charAt(0)+r.day?.slice(1).toLowerCase()||'', tdCols[1], y+2);
    doc.text(`€${Math.round(r.gross_total).toLocaleString()}`, tdCols[2], y+2);
    doc.text(`€${Math.round(r.net_total).toLocaleString()}`, tdCols[3], y+2);
    doc.text(String(r.ppl_rest_total), tdCols[4], y+2);
    doc.text(r.ppl_rest_total ? `€${(r.net_total/r.ppl_rest_total).toFixed(1)}` : '—', tdCols[5], y+2);
    y+=9;
  });
  y+=4;

  // Costs section (if available)
  const mc = costs[selYearK]||{};
  const hasAnyCost = Object.keys(mc).some(k=>typeof mc[k]==='object'&&mc[k].food_cost);
  if(hasAnyCost) {
    sectionTitle('Cost Analysis');
    const totFood  = Object.values(mc).filter(v=>typeof v==='object').reduce((a,m)=>a+(m.food_cost||0),0);
    const totLabor = Object.values(mc).filter(v=>typeof v==='object').reduce((a,m)=>a+(m.labor_cost||0),0);
    const totBevC  = Object.values(mc).filter(v=>typeof v==='object').reduce((a,m)=>a+(m.bev_cost||0),0);
    kpiRow([
      {label:'Food Cost %',    value: tN?`${(totFood/tN*100).toFixed(1)}%`:'—', sub:`€${Math.round(totFood).toLocaleString()}`, subColor:totFood/tN*100<=33?0:200},
      {label:'Bev Cost %',     value: tN?`${(totBevC/tN*100).toFixed(1)}%`:'—', sub:`€${Math.round(totBevC).toLocaleString()}`, subColor:totBevC/tN*100<=25?0:200},
      {label:'Labor Cost %',   value: tN?`${(totLabor/tN*100).toFixed(1)}%`:'—', sub:`€${Math.round(totLabor).toLocaleString()}`, subColor:totLabor/tN*100<=35?0:200},
      {label:'Prime Cost %',   value: tN?`${((totFood+totLabor)/tN*100).toFixed(1)}%`:'—', sub:'Food + Labor', subColor:(totFood+totLabor)/tN*100<=65?0:200},
    ]);
  }

  // Footer
  const pageCount=doc.getNumberOfPages();
  for(let i=1;i<=pageCount;i++){
    doc.setPage(i);
    doc.setFillColor(26,26,46);
    doc.rect(0,285,W,12,'F');
    doc.setFontSize(7); doc.setTextColor(100,100,100); doc.setFont('helvetica','normal');
    doc.text('Restaurant Intelligence Pro — Confidential Management Report', M, 292);
    doc.text(`Page ${i} of ${pageCount}`, W-M-15, 292);
  }

  const fname = `flash-report-${selYear}-${selMonth.toLowerCase()}.pdf`;
  doc.save(fname);
  toast('Flash Report downloaded ✓','success');
};



window.openPosImport = function() {
  $('pos-import-modal').style.display = 'block';
  $('pos-import-result').innerHTML = '';
  $('pos-file-input').value = '';
};


window.closePosImport = function() {
  $('pos-import-modal').style.display = 'none';
};


window.handlePosFile = function(evt) {
  const file = evt.target.files[0];
  if (!file) return;
  $('pos-import-result').innerHTML = `<div style="color:#f5c842;font-family:monospace;font-size:12px;padding:12px">📂 Reading ${file.name}...</div>`;

  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const data = new Uint8Array(e.target.result);
      const wb = XLSX.read(data, { type:'array', cellDates:true });
      const sheetName = wb.SheetNames[0];
      const ws = wb.Sheets[sheetName];
      const rows = XLSX.utils.sheet_to_json(ws, { header:1, defval:null });

      if (rows.length < 2) {
        $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ File appears empty or invalid</div>`;
        return;
      }

      const posType = $('pos-type-select').value;
      let colMap;

      if (posType === 'ri_template') {
        // Re-read with cellDates:false so dates are serial numbers (unambiguous)
        const wb2 = XLSX.read(data, { type:'array', cellDates:false });
        const ws2 = wb2.Sheets[wb2.SheetNames[0]];
        const rows2 = XLSX.utils.sheet_to_json(ws2, { header:1, defval:null, raw:true });
        const parsed = [];
        for (let i = 1; i < rows2.length; i++) {
          const r = parseRITemplateRow(rows2[i]);
          if (r) parsed.push(r);
        }
        if (!parsed.length) {
          $('pos-import-result').innerHTML = '<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ No valid rows found. Make sure Date column has valid dates and Gross Total > 0.</div>';
          return;
        }
        finalizePosImport(parsed, file.name, {});
        return;
      } else if (posType === 'auto') {
        // Auto-detect from headers
        const headerRow = rows[0].map(h => String(h||''));
        colMap = autoDetectColumns(headerRow);
        if (!colMap.dateCol && colMap.dateCol !== 0) colMap.dateCol = 0;
        if (!colMap.totalGross) {
          $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ Could not auto-detect columns. Please select your POS system or use the template.</div>`;
          return;
        }
      } else if (posType === 'geco') {
        // Use Geco template - skip header rows
        colMap = { ...POS_TEMPLATES.geco };
        const parsed = [];
        for (let i = POS_TEMPLATES.geco.dataStartRow; i < rows.length; i++) {
          const r = parseRow(rows[i], colMap);
          if (r) parsed.push(r);
        }
        finalizePosImport(parsed, file.name, colMap);
        return;
      } else {
        colMap = { ...POS_TEMPLATES[posType] };
      }

      const startRow = colMap.headerRow !== undefined ? colMap.headerRow + 1 : 1;
      const parsed = [];
      for (let i = startRow; i < rows.length; i++) {
        const r = parseRow(rows[i], colMap);
        if (r) parsed.push(r);
      }
      finalizePosImport(parsed, file.name, colMap);
    } catch(err) {
      $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ Error reading file: ${err.message}</div>`;
    }
  };
  reader.readAsArrayBuffer(file);
};

function finalizePosImport(parsed, fname, colMap) {
  if (!parsed.length) {
    $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ No valid data rows found. Check your file format and selected POS type.</div>`;
    return;
  }

  // Show preview
  const byYear = {};
  parsed.forEach(r => {
    if (!byYear[r.year]) byYear[r.year] = {count:0,gross:0,net:0,covers:0};
    byYear[r.year].count++;
    byYear[r.year].gross += r.gross;
    byYear[r.year].net   += r.net;
    byYear[r.year].covers+= r.ppl_rest_total;
  });

  $('pos-import-result').innerHTML = `
    <div style="background:rgba(0,212,170,.1);border:1px solid #00d4aa33;border-radius:8px;padding:16px;margin-top:12px">
      <div style="font-weight:700;color:#00d4aa;margin-bottom:10px;font-size:14px">✅ ${parsed.length} records ready to import from ${fname}</div>
      <table style="width:100%;border-collapse:collapse;font-family:monospace;font-size:12px">
        <tr style="color:#555;font-size:10px;text-transform:uppercase">
          <td style="padding:4px 8px">Year</td><td style="padding:4px 8px">Days</td>
          <td style="padding:4px 8px">Total Gross</td><td style="padding:4px 8px">Total Net</td>
          <td style="padding:4px 8px">Covers</td>
        </tr>
        ${Object.entries(byYear).sort((a,b)=>a[0]-b[0]).map(([yr,v])=>`
          <tr style="border-top:1px solid rgba(255,255,255,.06)">
            <td style="padding:6px 8px;color:#f5c842;font-weight:700">${yr}</td>
            <td style="padding:6px 8px">${v.count}</td>
            <td style="padding:6px 8px;color:#ff6b35">€${Math.round(v.gross).toLocaleString()}</td>
            <td style="padding:6px 8px;color:#00d4aa">€${Math.round(v.net).toLocaleString()}</td>
            <td style="padding:6px 8px">${v.covers.toLocaleString()}</td>
          </tr>`).join('')}
      </table>
      <div style="margin-top:12px;display:flex;gap:10px">
        <button onclick="confirmPosImport('merge')" style="flex:1;background:#00d4aa;color:#000;border:none;border-radius:8px;padding:10px;font-weight:700;cursor:pointer">
          🔀 Merge with existing data
        </button>
        <button onclick="confirmPosImport('replace')" style="flex:1;background:#ff6b35;color:#fff;border:none;border-radius:8px;padding:10px;font-weight:700;cursor:pointer">
          🔄 Replace all data
        </button>
      </div>
      <div style="font-size:10px;color:#555;margin-top:8px;font-family:monospace">
        Merge = keeps existing manual entries, adds new POS data (skips duplicates by date)<br>
        Replace = overwrites everything with POS data only
      </div>
    </div>`;

  window._posImportPending = parsed;
}


window.confirmPosImport = function(mode) {
  const parsed = window._posImportPending;
  if (!parsed) return;

  if (mode === 'replace') {
    records = parsed;
  } else {
    // Merge: add records for dates not already in records
    const existingDates = new Set(records.map(r => r.date));
    const newRecords = parsed.filter(r => !existingDates.has(r.date));
    records = [...records, ...newRecords].sort((a,b) => a.date.localeCompare(b.date));
    toast(`Merged: ${newRecords.length} new days added`, 'success');
  }

  saveRecords();
  setSyncStatus(`POS Import: ${records.length} records`);
  closePosImport();
  renderPage(currentTab);
  toast(`✅ Import complete: ${parsed.length} days loaded`, 'success');
  window._posImportPending = null;
};

// ── Download Excel Template ───────────────────────────────────────






// ═══════════════════════════════════════════════════════════════════
//  RESTAURANT INTELLIGENCE TEMPLATE IMPORT
//  37-column format: all fields for complete daily record
// ═══════════════════════════════════════════════════════════════════

// Column index map (matches the downloaded template exactly)
const RI_COL = {"Date": 0, "Day": 1, "Gross Breakfast": 2, "Gross Lunch": 3, "Gross Afternoon": 4, "Gross Dinner": 5, "Gross Bar": 6, "Net Breakfast": 7, "Net Lunch": 8, "Net Afternoon": 9, "Net Dinner": 10, "Net Bar": 11, "Gross Total Restaurant": 12, "Net Total Restaurant": 13, "Covers Breakfast": 14, "Covers Lunch": 15, "Covers Afternoon": 16, "Covers Dinner": 17, "Covers Bar": 18, "Covers Total": 19, "Total Invoices": 20, "Hotel Bfast Gross": 21, "Hotel Bfast Net": 22, "Hotel Bfast Covers": 23, "Food Breakfast": 24, "Bev Breakfast": 25, "Food Lunch": 26, "Bev Lunch": 27, "Food Afternoon": 28, "Bev Afternoon": 29, "Food Dinner": 30, "Bev Dinner": 31, "Food Bar": 32, "Bev Bar": 33, "Discounts Amount": 34, "Complimentary Amount": 35, "Notes": 36};

function parseRITemplateRow(row) {
  const g = (key) => {
    const idx = RI_COL[key];
    if (idx === undefined) return 0;
    const v = row[idx];
    const n = parseFloat(String(v||'').replace(/[€, ]/g,''));
    return isNaN(n) ? 0 : Math.round(n*100)/100;
  };
  const gi = (key) => Math.round(g(key));
  const gs = (key) => { const idx=RI_COL[key]; return idx!==undefined?String(row[idx]||'').trim():''; };

  // Parse date - handles YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY, Excel serial
  let ds = gs('Date');
  if (!ds || ds === 'Date') return null; // skip header row
  ds = String(ds).trim();
  // Excel serial number
  if (!isNaN(ds) && parseFloat(ds) > 40000) {
    const d = new Date(Math.round((parseFloat(ds) - 25569) * 86400 * 1000));
    ds = d.toISOString().slice(0,10);
  }
  // Already YYYY-MM-DD
  else if (!ds.match(/^\d{4}-\d{2}-\d{2}$/)) {
    const parts = ds.split(/[\/-]/);
    if (parts.length === 3) {
      let [a, b, c] = parts;
      if (c.length === 2) c = '20' + c;
      if (a.length === 4) {
        // YYYY-MM-DD or YYYY/MM/DD
        ds = `${a}-${b.padStart(2,'0')}-${c.padStart(2,'0')}`;
      } else if (parseInt(a) > 12) {
        // DD/MM/YYYY - day is > 12 so unambiguous
        ds = `${c}-${b.padStart(2,'0')}-${a.padStart(2,'0')}`;
      } else if (parseInt(b) > 12) {
        // MM/DD/YYYY - month is > 12 so unambiguous
        ds = `${c}-${a.padStart(2,'0')}-${b.padStart(2,'0')}`;
      } else {
        // Ambiguous - try MM/DD/YYYY first (US format from Excel)
        ds = `${c}-${a.padStart(2,'0')}-${b.padStart(2,'0')}`;
      }
    }
  }
  if (!ds.match(/^\d{4}-\d{2}-\d{2}$/)) return null;

  const year = parseInt(ds.slice(0,4));
  if (year < 2020 || year > 2030) return null;

  const MONTHS_ALL = ['JANUARY','FEBRUARY','MARCH','APRIL','MAY','JUNE','JULY',
                      'AUGUST','SEPTEMBER','OCTOBER','NOVEMBER','DECEMBER'];
  const DOW_ALL    = ['MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY','SUNDAY'];
  const dt = new Date(ds + 'T12:00:00');
  const month = MONTHS_ALL[dt.getMonth()];
  const dayIdx = dt.getDay();
  const day = DOW_ALL[dayIdx === 0 ? 6 : dayIdx - 1]; // always auto-calculate from date

  // Restaurant gross/net per segment
  const bfast_gross    = g('Gross Breakfast');
  const lunch_gross    = g('Gross Lunch');
  const afternoon_gross= g('Gross Afternoon');
  const dinner_gross   = g('Gross Dinner');
  const bar_gross      = g('Gross Bar');
  const bfast_net      = g('Net Breakfast')   || +(bfast_gross    * 0.86).toFixed(2);
  const lunch_net      = g('Net Lunch')       || +(lunch_gross     * 0.86).toFixed(2);
  const afternoon_net  = g('Net Afternoon')   || +(afternoon_gross * 0.86).toFixed(2);
  const dinner_net     = g('Net Dinner')      || +(dinner_gross    * 0.86).toFixed(2);
  const bar_net        = g('Net Bar')         || +(bar_gross       * 0.86).toFixed(2);

  // Totals — use explicit column if provided, else sum segments
  const gross_total = g('Gross Total Restaurant') ||
    +(bfast_gross+lunch_gross+afternoon_gross+dinner_gross+bar_gross).toFixed(2);
  const net_total   = g('Net Total Restaurant')   ||
    +(bfast_net+lunch_net+afternoon_net+dinner_net+bar_net).toFixed(2);

  if (!gross_total) return null;

  // Covers
  const ppl_bfast     = gi('Covers Breakfast');
  const ppl_lunch     = gi('Covers Lunch');
  const ppl_afternoon = gi('Covers Afternoon');
  const ppl_dinner    = gi('Covers Dinner');
  const ppl_bar       = gi('Covers Bar');
  const ppl_rest_total= gi('Covers Total') || ppl_bfast+ppl_lunch+ppl_afternoon+ppl_dinner+ppl_bar;

  // Hotel breakfast (completely separate)
  const hotel_bfast_gross  = g('Hotel Bfast Gross');
  const hotel_bfast_net    = g('Hotel Bfast Net')    || +(hotel_bfast_gross * 0.86).toFixed(2);
  const hotel_bfast_covers = gi('Hotel Bfast Covers');

  return {
    year, month, date: ds, day,
    gross: gross_total, net: net_total,
    gross_total, net_total,
    rest_gross: gross_total, rest_net: net_total,
    bfast_gross, bfast_net,
    lunch_gross, lunch_net,
    afternoon_gross, afternoon_net,
    dinner_gross, dinner_net,
    bar_gross, bar_net,
    event_lunch_gross:0, event_lunch_net:0,
    event_afternoon_gross:0, event_afternoon_net:0,
    event_dinner_gross:0, event_dinner_net:0,
    bar_event_gross:0, bar_event_net:0,
    ppl_rest_total, ppl_total: gi('Total Invoices') || ppl_rest_total,
    ppl_bfast, ppl_lunch, ppl_afternoon, ppl_event:0, ppl_dinner, ppl_bar,
    ppl_avg: ppl_rest_total ? +(net_total/ppl_rest_total).toFixed(2) : 0,
    avg_bfast:     ppl_bfast     ? +(bfast_net/ppl_bfast).toFixed(2)         : 0,
    avg_lunch:     ppl_lunch     ? +(lunch_net/ppl_lunch).toFixed(2)          : 0,
    avg_afternoon: ppl_afternoon ? +(afternoon_net/ppl_afternoon).toFixed(2)  : 0,
    avg_event: 0,
    avg_dinner:    ppl_dinner    ? +(dinner_net/ppl_dinner).toFixed(2)        : 0,
    avg_bar:       ppl_bar       ? +(bar_net/ppl_bar).toFixed(2)              : 0,
    avg_total: ppl_rest_total ? +(net_total/ppl_rest_total).toFixed(2) : 0,
    // Food vs Beverage split
    food_bfast:     g('Food Breakfast'),  bev_bfast:     g('Bev Breakfast'),
    food_lunch:     g('Food Lunch'),      bev_lunch:     g('Bev Lunch'),
    food_afternoon: g('Food Afternoon'),  bev_afternoon: g('Bev Afternoon'),
    food_dinner:    g('Food Dinner'),     bev_dinner:    g('Bev Dinner'),
    food_bar:       g('Food Bar'),        bev_bar:       g('Bev Bar'),
    // Hotel breakfast
    hotel_bfast_gross, hotel_bfast_net, hotel_bfast_covers,
    // Discounts
    discounts_amt:    g('Discounts Amount'),
    discounts_pct:    gross_total ? g('Discounts Amount')/gross_total : 0,
    complimentary_amt: g('Complimentary Amount'),
    complimentary_pct: gross_total ? g('Complimentary Amount')/gross_total : 0,
    staff_cost_total:0, op_exp_total:0, profit_loss_amt:0, profit_loss_pct:0,
    notes: gs('Notes'), source: 'template_import',
  };
}

// ── Updated downloadPosTemplate — generates the 37-column template ──
window.downloadPosTemplate = function() {
  const headers = ["Date", "Day", "Gross Breakfast", "Gross Lunch", "Gross Afternoon", "Gross Dinner", "Gross Bar", "Net Breakfast", "Net Lunch", "Net Afternoon", "Net Dinner", "Net Bar", "Gross Total Restaurant", "Net Total Restaurant", "Covers Breakfast", "Covers Lunch", "Covers Afternoon", "Covers Dinner", "Covers Bar", "Covers Total", "Total Invoices", "Hotel Bfast Gross", "Hotel Bfast Net", "Hotel Bfast Covers", "Food Breakfast", "Bev Breakfast", "Food Lunch", "Bev Lunch", "Food Afternoon", "Bev Afternoon", "Food Dinner", "Bev Dinner", "Food Bar", "Bev Bar", "Discounts Amount", "Complimentary Amount", "Notes"];
  const example = ["2024-01-01", "Monday", 56.5, 3081.1, 1976.0, 3688.5, 0, 49.99, 2686.63, 1681.32, 3124.34, 0, 8802.1, 7542.28, 10, 123, 59, 131, 0, 323, 91, 953.0, 843.36, 19, 120.62, 63.95, 984.75, 477.52, 444.02, 174.41, 3058.93, 1789.34, 0, 0, 246.6, 265.5, ""];
  const wb = XLSX.utils.book_new();
  const ws = XLSX.utils.aoa_to_sheet([headers, example]);
  // Column widths
  ws['!cols'] = headers.map(h => ({wch: Math.max(h.length+2, 12)}));
  // Style header row (bold) via cell format
  headers.forEach((h, i) => {
    const cell = XLSX.utils.encode_cell({r:0, c:i});
    if (!ws[cell]) return;
    ws[cell].s = {font:{bold:true}, fill:{fgColor:{rgb:'1a1a2e'}}, alignment:{horizontal:'center'}};
  });
  XLSX.utils.book_append_sheet(wb, ws, 'Daily Sales');

  // Add a Notes sheet explaining each column
  const notes = [
    ['Column', 'Description', 'Required', 'Format'],
    ['Date', 'Date of the day', 'YES', 'YYYY-MM-DD'],
    ['Day', 'Day of week (auto-calculated if blank)', 'NO', 'Monday/Tuesday/...'],
    ['Gross Breakfast', 'Restaurant breakfast gross revenue', 'NO', '€ number'],
    ['Gross Lunch', 'Lunch gross revenue', 'NO', '€ number'],
    ['Gross Afternoon', 'Afternoon gross revenue', 'NO', '€ number'],
    ['Gross Dinner', 'Dinner gross revenue (most important)', 'YES', '€ number'],
    ['Gross Bar', 'Bar/after midnight gross', 'NO', '€ number'],
    ['Net Breakfast/Lunch/etc', 'Net revenue — LEAVE BLANK = auto 86%', 'NO', '€ number'],
    ['Gross Total Restaurant', 'Total restaurant gross (sum of segments)', 'YES', '€ number'],
    ['Net Total Restaurant', 'Total restaurant net', 'NO', '€ number or blank'],
    ['Covers Breakfast/Lunch/etc', 'Guest count per time zone', 'NO', 'integer'],
    ['Covers Total', 'Total restaurant covers', 'YES', 'integer'],
    ['Total Invoices', 'Number of bills/checks issued', 'NO', 'integer'],
    ['Hotel Bfast Gross', 'HOTEL breakfast revenue (separate!)', 'NO', '€ number'],
    ['Hotel Bfast Net', 'Hotel breakfast net', 'NO', '€ number or blank'],
    ['Hotel Bfast Covers', 'Hotel breakfast guests', 'NO', 'integer'],
    ['Food Breakfast/Lunch/etc', 'Food portion of each time zone net', 'NO', '€ number'],
    ['Bev Breakfast/Lunch/etc', 'Beverage portion of each time zone net', 'NO', '€ number'],
    ['Discounts Amount', 'Total discounts given (€)', 'NO', '€ number'],
    ['Complimentary Amount', 'Total complimentary (€)', 'NO', '€ number'],
    ['Notes', 'Free text notes for the day', 'NO', 'text'],
  ];
  const ws2 = XLSX.utils.aoa_to_sheet(notes);
  ws2['!cols'] = [{wch:30},{wch:50},{wch:12},{wch:20}];
  XLSX.utils.book_append_sheet(wb, ws2, 'Column Guide');

  XLSX.writeFile(wb, 'restaurant-intelligence-template.xlsx');
  toast('Template downloaded ✓ — 37 columns with guide sheet', 'success');
};

// ── Updated handlePosFile — detect RI template and parse correctly ──
window.handleRITemplateFile = function(evt) {
  const file = evt.target.files[0];
  if (!file) return;
  $('pos-import-result').innerHTML = `<div style="color:#f5c842;font-family:monospace;font-size:12px;padding:12px">📂 Reading ${file.name}...</div>`;
  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const data = new Uint8Array(e.target.result);
      const wb = XLSX.read(data, { type:'array', cellDates:false });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { header:1, defval:null, raw:true });
      if (rows.length < 2) { toast('File empty or invalid','error'); return; }

      const parsed = [];
      for (let i = 1; i < rows.length; i++) { // skip header
        const r = parseRITemplateRow(rows[i]);
        if (r) parsed.push(r);
      }
      finalizePosImport(parsed, file.name, {});
    } catch(err) {
      $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ ${err.message}</div>`;
    }
  };
  reader.readAsArrayBuffer(file);
};

