function renderRepDiscounts(R) {
  const MONTHS_L = ['January','February','March','April','May','June','July',
                    'August','September','October','November','December'];
  const MONTHS_S = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const dc = R.disc_comp;

  $('rep-content').innerHTML = `
    <!-- Year totals KPI cards -->
    <div class="grid4" style="margin-bottom:12px">
      ${[2024,2025,2026].map(yr=>{
        const d=dc?.[yr]||{}; if(!d.net) return '';
        return `<div class="card" style="border-top-color:${yr===2024?'#f5c842':yr===2025?'#00d4aa':'#ff6b35'}">
          <div class="ct">${yr} DISC + COMP</div>
          <div style="font-size:22px;font-weight:900;color:${yr===2024?'#f5c842':yr===2025?'#00d4aa':'#ff6b35'};font-family:monospace">${fmt(d.disc+d.comp)}</div>
          <div style="font-size:12px;color:#888;margin-top:4px">
            Disc: <span style="color:#ff4466">${fmt(d.disc)}</span>
            <span style="color:#555;margin:0 4px">·</span>
            <span style="color:#ff446688">${d.disc_pct}% of net</span>
          </div>
          <div style="font-size:12px;color:#888;margin-top:2px">
            Comp: <span style="color:#ff9f43">${fmt(d.comp)}</span>
            <span style="color:#555;margin:0 4px">·</span>
            <span style="color:#ff9f4388">${d.comp_pct}% of net</span>
          </div>
        </div>`;
      }).join('')}
    </div>

    <!-- Line charts -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card"><div class="ct">Discounts by Month — All Years</div>
        <div style="position:relative;height:220px"><canvas id="ch-disc-monthly"></canvas></div></div>
      <div class="card"><div class="ct">Complimentary by Month — All Years</div>
        <div style="position:relative;height:220px"><canvas id="ch-comp-monthly"></canvas></div></div>
    </div>

    <!-- Monthly detail table with % -->
    <div class="card" style="margin-bottom:12px">
      <div class="ct">Monthly Discounts + Complimentary Detail</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>
            ${['Month',
               '2024 Net','2024 Disc','Disc %','2024 Comp','Comp %',
               '2025 Net','2025 Disc','Disc %','2025 Comp','Comp %',
               '2026 Net','2026 Disc','Disc %','2026 Comp','Comp %'].map(h=>
              `<th style="padding:6px 8px;font-family:monospace;font-size:9px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`
            ).join('')}
          </tr></thead>
          <tbody>
            ${MONTHS_L.map((m,i)=>{
              const d24=dc?.[2024]?.monthly?.[m]||{}, d25=dc?.[2025]?.monthly?.[m]||{}, d26=dc?.[2026]?.monthly?.[m]||{};
              if(!d24.net&&!d25.net&&!d26.net) return '';
              const cell=(n,d,c,dp,cp)=>!n?'<td colspan="5" style="color:#333;text-align:center;padding:6px 8px">—</td>':
                `<td class="mono" style="padding:6px 8px;color:#888;font-size:11px">${fmt(n)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff4466;font-size:11px">${fmt(d)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff446688;font-size:10px">${dp}%</td>
                 <td class="mono" style="padding:6px 8px;color:#ff9f43;font-size:11px">${fmt(c)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff9f4388;font-size:10px">${cp}%</td>`;
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                <td style="padding:6px 8px;font-weight:700;font-size:12px">${MONTHS_S[i]}</td>
                ${cell(d24.net,d24.disc,d24.comp,d24.disc_pct,d24.comp_pct)}
                ${cell(d25.net,d25.disc,d25.comp,d25.disc_pct,d25.comp_pct)}
                ${cell(d26.net,d26.disc,d26.comp,d26.disc_pct,d26.comp_pct)}
              </tr>`;
            }).join('')}
            <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
              <td style="padding:6px 8px">TOTAL</td>
              ${[2024,2025,2026].map(yr=>{
                const d=dc?.[yr]||{};
                return `<td class="mono" style="padding:6px 8px;color:#888;font-size:11px">${fmt(d.net||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff4466;font-size:11px">${fmt(d.disc||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff446688;font-size:10px">${d.disc_pct||0}%</td>
                        <td class="mono" style="padding:6px 8px;color:#ff9f43;font-size:11px">${fmt(d.comp||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff9f4388;font-size:10px">${d.comp_pct||0}%</td>`;
              }).join('')}
            </tr>
          </tbody>
        </table>
      </div>
    </div>`;

  // Line charts
  mkLine('ch-disc-monthly', MONTHS_S, [
    {label:'2024',data:MONTHS_L.map(m=>dc?.[2024]?.monthly?.[m]?.disc||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025',data:MONTHS_L.map(m=>dc?.[2025]?.monthly?.[m]?.disc||null),borderColor:'#00d4aa',backgroundColor:'#00d4aa22'},
    {label:'2026',data:MONTHS_L.map(m=>dc?.[2026]?.monthly?.[m]?.disc||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
  mkLine('ch-comp-monthly', MONTHS_S, [
    {label:'2024',data:MONTHS_L.map(m=>dc?.[2024]?.monthly?.[m]?.comp||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025',data:MONTHS_L.map(m=>dc?.[2025]?.monthly?.[m]?.comp||null),borderColor:'#00d4aa',backgroundColor:'#00d4aa22'},
    {label:'2026',data:MONTHS_L.map(m=>dc?.[2026]?.monthly?.[m]?.comp||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
}


function renderHotelBreakfast() {
  // Merge static Excel hotel data with manually added records
  const excelHd = EXCEL_DATA.hotel_daily || [];

  // Build a set of dates already in excel data
  const excelDates = new Set(excelHd.map(r => r.date));

  // Get manual records that have hotel breakfast data
  const manualHd = records
    .filter(r => r.source === 'manual' && (r.hotel_bfast_gross || r.hotel_bfast_net) && !excelDates.has(r.date))
    .map(r => ({
      date:    r.date,
      year:    r.year,
      month:   r.month ? (r.month.charAt(0).toUpperCase() + r.month.slice(1).toLowerCase()) : '',
      gross:   r.hotel_bfast_gross || 0,
      net:     r.hotel_bfast_net   || 0,
      covers:  r.hotel_bfast_covers || r.ppl_bfast || 0,
      avg:     (r.hotel_bfast_covers||r.ppl_bfast) ? (r.hotel_bfast_net||(r.hotel_bfast_gross*0.86)) / (r.hotel_bfast_covers||r.ppl_bfast) : 0,
    }));

  // Also update existing excel records if a manual entry exists for same date
  const manualUpdates = records
    .filter(r => r.source === 'manual' && (r.hotel_bfast_gross || r.hotel_bfast_net) && excelDates.has(r.date))
    .reduce((acc, r) => { acc[r.date] = r; return acc; }, {});

  const hd = [
    ...excelHd.map(r => {
      const upd = manualUpdates[r.date];
      if (!upd) return r;
      return {
        ...r,
        gross:   (r.gross   || 0) + (upd.hotel_bfast_gross || 0),
        net:     (r.net     || 0) + (upd.hotel_bfast_net   || 0),
        covers:  (r.covers  || 0) + (upd.hotel_bfast_covers || upd.ppl_bfast || 0),
      };
    }),
    ...manualHd,
  ].sort((a, b) => a.date.localeCompare(b.date));
  const MONTHS_L=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTHS_S=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const monthMap={'JAN':'January','FEB':'February','MAR':'March','APR':'April','MAY':'May','JUN':'June','JUL':'July','AUG':'August','SEP':'September','OCT':'October','NOV':'November','DEC':'December'};

  // Apply BOTH year and month filters from the global filter state
  const selYear = yearFilter === 'ALL' ? null : parseInt(yearFilter);
  const selMonthFull = monthFilter === 'ALL' ? null : (monthMap[monthFilter] || MONTHS_L.find(m=>m.toUpperCase().startsWith(monthFilter.slice(0,3))));
  const d = hd.filter(r=>(!selYear||r.year===selYear)&&(!selMonthFull||r.month===selMonthFull));

  const tG = d.reduce((a,r)=>a+r.gross,0);
  const tN = d.reduce((a,r)=>a+r.net,0);
  const tC = d.reduce((a,r)=>a+r.covers,0);
  const asp = tC ? tN/tC : 0;
  // Charts use year filter only (show monthly breakdown)
  const hdYear = selYear ? hd.filter(r=>r.year===selYear) : hd;
  const yrs = selYear ? [selYear] : [...new Set(hd.map(r=>r.year))].sort();

  $('hb-page-kpis').innerHTML = [
    kpiHtml('Total Gross',fmt(tG),'#f5c842',(selYear||'All years')+(selMonthFull?' · '+selMonthFull.slice(0,3):'')+' · '+d.length+' days'),
    kpiHtml('Total Net',fmt(tN),'#f5c842',tG?((tN/tG)*100).toFixed(1)+'% margin':'—'),
    kpiHtml('Total Covers',fmtN(tC),'#7c5cfc',Math.round(tC/(d.length||1))+' avg/day'),
    kpiHtml('Avg / Cover',fmt(asp),'#00d4aa','net per hotel guest'),
  ].join('');

  // Monthly chart
  mkChart('ch-hb-monthly',{
    type:'bar',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          return r.length?r.reduce((a,x)=>a+x.gross,0):null;
        }),
        backgroundColor:YEAR_COLORS[y]+'cc',borderRadius:4,borderSkipped:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v/1000)+'k'}}}}
  });

  // Covers by year
  mkChart('ch-hb-covers',{
    type:'line',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          return r.length?r.reduce((a,x)=>a+x.covers,0):null;
        }),
        borderColor:YEAR_COLORS[y],backgroundColor:YEAR_COLORS[y]+'22',
        borderWidth:2,pointRadius:4,tension:.3,fill:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555'}}}}
  });

  // Avg/cover by year
  mkChart('ch-hb-avg',{
    type:'line',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          if(!r.length) return null;
          const tNm=r.reduce((a,x)=>a+x.net,0), tCm=r.reduce((a,x)=>a+x.covers,0);
          return tCm?+(tNm/tCm).toFixed(2):null;
        }),
        borderColor:YEAR_COLORS[y],backgroundColor:YEAR_COLORS[y]+'22',
        borderWidth:2,pointRadius:4,tension:.3,fill:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+v.toFixed(1)}}}}
  });

  // Monthly detail table
  // Build monthly summary from filtered data
  // Build monthly summary from merged hd data
  const hbmMap = {};
  hd.forEach(r => {
    const mName = r.month ? (r.month.charAt(0).toUpperCase() + r.month.slice(1).toLowerCase()) : '';
    const key = r.year + '-' + mName;
    if (!hbmMap[key]) hbmMap[key] = {year:r.year, month:mName, gross:0, net:0, covers:0, days:0};
    hbmMap[key].gross   += r.gross;
    hbmMap[key].net     += r.net;
    hbmMap[key].covers  += r.covers;
    hbmMap[key].days    += 1;
  });
  const hbm = Object.values(hbmMap);
  // For the table, show months relevant to the filter
  const tableMonths = selMonthFull ? [selMonthFull] : MONTHS_L;
  $('hb-page-table').innerHTML=`
    <table style="width:100%;border-collapse:collapse">
      <thead><tr>
        ${['Month','Year','Days','Gross','Net','Margin','Covers','Avg/Cover'].map(h=>`<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`).join('')}
      </tr></thead>
      <tbody>
        ${tableMonths.flatMap(m=>yrs.map(y=>{
          const r=hbm.find(x=>x.year==y&&x.month===m);
          if(!r||r.gross===0) return '';
          return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
            <td style="padding:7px 10px;font-weight:700">${m.slice(0,3)}</td>
            <td><span style="color:${YEAR_COLORS[y]};font-weight:700">${y}</span></td>
            <td class="mono" style="padding:7px 10px">${r.days}</td>
            <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(r.gross)}</td>
            <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(r.net)}</td>
            <td class="mono" style="padding:7px 10px">${r.gross?((r.net/r.gross)*100).toFixed(1)+'%':'—'}</td>
            <td class="mono" style="padding:7px 10px">${fmtN(r.covers)}</td>
            <td class="mono" style="padding:7px 10px;color:#00d4aa">${r.covers?'€'+(r.net/r.covers).toFixed(1):'—'}</td>
          </tr>`;
        })).join('')}
        <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
          <td colspan="3" style="padding:7px 10px">TOTAL (filtered)</td>
          <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(tG)}</td>
          <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(tN)}</td>
          <td class="mono" style="padding:7px 10px">${tG?((tN/tG)*100).toFixed(1)+'%':'—'}</td>
          <td class="mono" style="padding:7px 10px">${fmtN(tC)}</td>
          <td class="mono" style="padding:7px 10px;color:#00d4aa">${tC?'€'+(tN/tC).toFixed(1):'—'}</td>
        </tr>
      </tbody>
    </table>`;
}

// ═══════════════════════════════════════════════════════════════════
//  FOOD & BEVERAGE PAGE
// ═══════════════════════════════════════════════════════════════════

function renderFandB() {
  const FB = FB_DATA;
  const MONTHS_L = ['January','February','March','April','May','June','July',
                    'August','September','October','November','December'];
  const MONTHS_S = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const SHIFTS   = ['Breakfast','Lunch','Afternoon','Dinner'];
  const YC = {'2024':'#f5c842','2025':'#00d4aa','2026':'#ff6b35'};
  const el = $('fandb-content'); if(!el) return;

  window._fbYear  = window._fbYear  || '2025';
  window._fbMonth = window._fbMonth || 'ALL';
  const selYr = window._fbYear;
  const selMo = window._fbMonth;

  const yrData = FB[selYr] || {};
  const months = MONTHS_L.filter(m => yrData[m]);
  const activeMonths = selMo === 'ALL' ? months : months.filter(m => m === selMo);

  let tFood=0, tBev=0, tCov=0;
  activeMonths.forEach(m => {
    const t = yrData[m]?.totals || {};
    tFood += t.food||0; tBev += t.bev||0; tCov += t.covers||0;
  });
  const tTotal = tFood + tBev;

  el.innerHTML = `
    <!-- KPI cards -->
    <div class="grid4" style="margin-bottom:12px">
      ${kpiHtml('Food (Restaurant)', fmt(tFood), '#00d4aa', tTotal?(tFood/tTotal*100).toFixed(1)+'% of total':'')}
      ${kpiHtml('Beverage (Bar)',    fmt(tBev),  '#7c5cfc', tTotal?(tBev/tTotal*100).toFixed(1)+'% of total':'')}
      ${kpiHtml('Total F&B',        fmt(tTotal), '#ff6b35', selYr+(selMo!=='ALL'?' · '+selMo:' · All months'))}
      ${kpiHtml('Total Covers',     fmtN(tCov), '#f5c842', tCov?'€'+(tTotal/tCov).toFixed(2)+' avg/cover':'')}
    </div>

    <!-- Year + Month selectors -->
    <div style="display:flex;gap:8px;align-items:center;margin-bottom:12px;flex-wrap:wrap">
      <span style="font-family:monospace;font-size:11px;color:#555">YEAR:</span>
      ${['2024','2025','2026'].map(y=>`<button onclick="window._fbYear='${y}';window._fbMonth='ALL';window.renderFandB()" class="pill-btn ${selYr===y?'on':''}">${y}</button>`).join('')}
      <div style="width:1px;height:20px;background:rgba(255,255,255,.1);margin:0 4px"></div>
      <span style="font-family:monospace;font-size:11px;color:#555">MONTH:</span>
      <button onclick="window._fbMonth='ALL';window.renderFandB()" class="pill-btn ${selMo==='ALL'?'on':''}">All</button>
      ${MONTHS_S.map((ms,i)=>{
        const ml=MONTHS_L[i];
        return yrData[ml]?`<button onclick="window._fbMonth='${ml}';window.renderFandB()" class="pill-btn ${selMo===ml?'on':''}" style="font-size:10px">${ms}</button>`:'';
      }).join('')}
    </div>

    <!-- Charts row -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card">
        <div class="ct">Food vs Beverage by Month — ${selYr}</div>
        <div style="position:relative;height:240px"><canvas id="ch-fb-monthly"></canvas></div>
      </div>
      <div class="card">
        <div class="ct">By Time Zone — ${selMo==='ALL'?selYr:selMo+' '+selYr}</div>
        <div style="position:relative;height:240px"><canvas id="ch-fb-shift"></canvas></div>
      </div>
    </div>

    <!-- YoY line charts -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card">
        <div class="ct">Food Revenue — 2024 vs 2025 vs 2026</div>
        <div style="position:relative;height:200px"><canvas id="ch-fb-yoy-food"></canvas></div>
      </div>
      <div class="card">
        <div class="ct">Beverage Revenue — 2024 vs 2025 vs 2026</div>
        <div style="position:relative;height:200px"><canvas id="ch-fb-yoy-bev"></canvas></div>
      </div>
    </div>

    <!-- Monthly table -->
    <div class="card" style="margin-bottom:12px">
      <div class="ct">Monthly Food & Beverage Detail — ${selYr}</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>${['Month','Food (Rest.)','Beverage (Bar)','Total F&B','Food %','Bev %','Covers','Avg/Cover'].map(h=>`<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`).join('')}</tr></thead>
          <tbody>
            ${MONTHS_L.map((m,i)=>{
              const d=yrData[m]?.totals; if(!d||!d.total) return '';
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03);${selMo===m?'background:rgba(255,107,53,.08)':''}">
                <td style="padding:7px 10px;font-weight:700${selMo===m?';color:#ff6b35':''}">${MONTHS_S[i]}</td>
                <td class="mono" style="padding:7px 10px;color:#00d4aa">${fmt(d.food)}</td>
                <td class="mono" style="padding:7px 10px;color:#7c5cfc">${fmt(d.bev)}</td>
                <td class="mono" style="padding:7px 10px;font-weight:700">${fmt(d.total)}</td>
                <td style="padding:7px 10px"><span style="background:rgba(0,212,170,.15);color:#00d4aa;border-radius:4px;padding:2px 6px;font-size:11px">${d.food_pct}%</span></td>
                <td style="padding:7px 10px"><span style="background:rgba(124,92,252,.15);color:#7c5cfc;border-radius:4px;padding:2px 6px;font-size:11px">${d.bev_pct}%</span></td>
                <td class="mono" style="padding:7px 10px">${fmtN(d.covers)}</td>
                <td class="mono" style="padding:7px 10px;color:#f5c842">${d.covers?'€'+(d.total/d.covers).toFixed(2):'—'}</td>
              </tr>`;
            }).join('')}
            <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
              <td style="padding:7px 10px">TOTAL</td>
              <td class="mono" style="padding:7px 10px;color:#00d4aa">${fmt(tFood)}</td>
              <td class="mono" style="padding:7px 10px;color:#7c5cfc">${fmt(tBev)}</td>
              <td class="mono" style="padding:7px 10px">${fmt(tTotal)}</td>
              <td style="padding:7px 10px;color:#00d4aa">${tTotal?(tFood/tTotal*100).toFixed(1)+'%':'—'}</td>
              <td style="padding:7px 10px;color:#7c5cfc">${tTotal?(tBev/tTotal*100).toFixed(1)+'%':'—'}</td>
              <td class="mono" style="padding:7px 10px">${fmtN(tCov)}</td>
              <td class="mono" style="padding:7px 10px;color:#f5c842">${tCov?'€'+(tTotal/tCov).toFixed(2):'—'}</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- Time zone table -->
    <div class="card" style="margin-bottom:12px">
      <div class="ct">By Time Zone — ${selMo==='ALL'?selYr:selMo+' '+selYr}</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>${['Time Zone','Food','Beverage','Total','Food %','Bev %','Covers','Avg/Cover'].map(h=>`<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`).join('')}</tr></thead>
          <tbody>
            ${(()=>{
              const SC={Breakfast:'#f5c842',Lunch:'#00d4aa',Afternoon:'#7c5cfc',Dinner:'#ff6b35'};
              return SHIFTS.map(shift=>{
                let food=0,bev=0,cov=0;
                activeMonths.forEach(m=>{const s=yrData[m]?.shifts?.[shift]||{};food+=s.food||0;bev+=s.bev||0;cov+=s.covers||0;});
                const tot=food+bev; if(!tot) return '';
                return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                  <td style="padding:7px 10px"><span style="color:${SC[shift]};font-weight:700">${shift}</span></td>
                  <td class="mono" style="padding:7px 10px;color:#00d4aa">${fmt(food)}</td>
                  <td class="mono" style="padding:7px 10px;color:#7c5cfc">${fmt(bev)}</td>
                  <td class="mono" style="padding:7px 10px;font-weight:700">${fmt(tot)}</td>
                  <td style="padding:7px 10px;color:#00d4aa">${(food/tot*100).toFixed(1)}%</td>
                  <td style="padding:7px 10px;color:#7c5cfc">${(bev/tot*100).toFixed(1)}%</td>
                  <td class="mono" style="padding:7px 10px">${fmtN(cov)}</td>
                  <td class="mono" style="padding:7px 10px;color:#f5c842">${cov?'€'+(tot/cov).toFixed(2):'—'}</td>
                </tr>`;
              }).join('');
            })()}
          </tbody>
        </table>
      </div>
    </div>

    <!-- 3-year comparison -->
    <div class="card">
      <div class="ct">Year vs Year — Food & Beverage by Month</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead>
            <tr>
              <th rowspan="2" style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">Month</th>
              ${['2024','2025','2026'].map(y=>`<th colspan="3" style="padding:6px 10px;font-family:monospace;font-size:10px;color:${YC[y]};text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.04);background:#16161f;text-align:center">${y}</th>`).join('')}
            </tr>
            <tr>
              ${['2024','2025','2026'].map(()=>`
                <th style="padding:4px 8px;font-family:monospace;font-size:9px;color:#00d4aa;border-bottom:1px solid rgba(255,255,255,.07);background:#0d0d1a">Food</th>
                <th style="padding:4px 8px;font-family:monospace;font-size:9px;color:#7c5cfc;border-bottom:1px solid rgba(255,255,255,.07);background:#0d0d1a">Bev</th>
                <th style="padding:4px 8px;font-family:monospace;font-size:9px;color:#888;border-bottom:1px solid rgba(255,255,255,.07);background:#0d0d1a">Total</th>
              `).join('')}
            </tr>
          </thead>
          <tbody>
            ${MONTHS_L.map((m,mi)=>{
              if(!['2024','2025','2026'].some(y=>FB[y]?.[m]?.totals?.total)) return '';
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                <td style="padding:6px 10px;font-weight:700">${MONTHS_S[mi]}</td>
                ${['2024','2025','2026'].map(y=>{const d=FB[y]?.[m]?.totals||{};return `
                  <td class="mono" style="padding:5px 8px;color:#00d4aa88;font-size:11px">${d.food?fmtK(d.food):'—'}</td>
                  <td class="mono" style="padding:5px 8px;color:#7c5cfc88;font-size:11px">${d.bev?fmtK(d.bev):'—'}</td>
                  <td class="mono" style="padding:5px 8px;color:${YC[y]};font-size:11px;font-weight:700">${d.total?fmtK(d.total):'—'}</td>`;}).join('')}
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>
    </div>`;

  // ── Charts ─────────────────────────────────────────────────
  const mLabels = MONTHS_S.filter((_,i) => yrData[MONTHS_L[i]]);
  const mMonths = MONTHS_L.filter(m => yrData[m]);

  mkChart('ch-fb-monthly', {type:'bar', data:{labels:mLabels, datasets:[
    {label:'Food (Restaurant)', data:mMonths.map(m=>yrData[m]?.totals?.food||0), backgroundColor:'#00d4aa99', borderRadius:4, borderSkipped:false},
    {label:'Beverage (Bar)',    data:mMonths.map(m=>yrData[m]?.totals?.bev||0),  backgroundColor:'#7c5cfc99', borderRadius:4, borderSkipped:false},
  ]}, options:{responsive:true,maintainAspectRatio:false,
    plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10}}},
    scales:{x:{stacked:true,grid:{color:GC},ticks:{color:'#555'}},y:{stacked:true,grid:{color:GC},ticks:{color:'#555',callback:v=>fmtK(v)}}}}
  });

  mkChart('ch-fb-shift', {type:'bar', data:{labels:SHIFTS, datasets:[
    {label:'Food', data:SHIFTS.map(s=>activeMonths.reduce((a,m)=>a+(yrData[m]?.shifts?.[s]?.food||0),0)), backgroundColor:'#00d4aacc', borderRadius:4, borderSkipped:false},
    {label:'Bev',  data:SHIFTS.map(s=>activeMonths.reduce((a,m)=>a+(yrData[m]?.shifts?.[s]?.bev||0),0)),  backgroundColor:'#7c5cfccc', borderRadius:4, borderSkipped:false},
  ]}, options:{responsive:true,maintainAspectRatio:false,
    plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10}}},
    scales:{x:{stacked:true,grid:{color:GC},ticks:{color:'#555'}},y:{stacked:true,grid:{color:GC},ticks:{color:'#555',callback:v=>fmtK(v)}}}}
  });

  mkLine('ch-fb-yoy-food', MONTHS_S, [
    {label:'2024 Food',data:MONTHS_L.map(m=>FB['2024']?.[m]?.totals?.food||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025 Food',data:MONTHS_L.map(m=>FB['2025']?.[m]?.totals?.food||null),borderColor:'#00d4aa',backgroundColor:'#00d4aa22'},
    {label:'2026 Food',data:MONTHS_L.map(m=>FB['2026']?.[m]?.totals?.food||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
  mkLine('ch-fb-yoy-bev', MONTHS_S, [
    {label:'2024 Bev',data:MONTHS_L.map(m=>FB['2024']?.[m]?.totals?.bev||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025 Bev',data:MONTHS_L.map(m=>FB['2025']?.[m]?.totals?.bev||null),borderColor:'#7c5cfc',backgroundColor:'#7c5cfc22'},
    {label:'2026 Bev',data:MONTHS_L.map(m=>FB['2026']?.[m]?.totals?.bev||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
}


// Expose render functions called from inline onclick handlers
window.renderFandB = renderFandB;
window.renderRepTimezones = renderRepTimezones;
window.renderRepWeekday = renderRepWeekday;
window.renderRepTickets = renderRepTickets;
window.renderRepDiscounts = renderRepDiscounts;
window.renderRepMonthly = renderRepMonthly;

function loadBudgets()  { try { return JSON.parse(localStorage.getItem(BUDGET_KEY)||'{}'); } catch{return {};} }
function saveBudgets(b) { try { localStorage.setItem(BUDGET_KEY, JSON.stringify(b)); clearTimeout(window._settingsTimer); window._settingsTimer=setTimeout(()=>window.cloudSaveSettings(),2000); } catch{} }
function loadMenu()     { try { return JSON.parse(localStorage.getItem(MENU_KEY)||'[]');  } catch{return [];} }
function saveMenu(m)    { try { localStorage.setItem(MENU_KEY, JSON.stringify(m)); clearTimeout(window._settingsTimer); window._settingsTimer=setTimeout(()=>window.cloudSaveSettings(),2000); } catch{} }
function loadCosts()    { try { return JSON.parse(localStorage.getItem(COSTS_KEY)||'{}'); } catch{return {};} }
function saveCosts(c)   { try { localStorage.setItem(COSTS_KEY, JSON.stringify(c)); clearTimeout(window._settingsTimer); window._settingsTimer=setTimeout(()=>window.cloudSaveSettings(),2000); } catch{} }
function loadSeats()    { try { return parseInt(localStorage.getItem(SEATS_KEY)||'80'); } catch{return 80;} }
function saveSeats(n)   { try { localStorage.setItem(SEATS_KEY, String(n)); } catch{} }


function renderBudget() {
  const budgets = loadBudgets();
  const MONTHS_L = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTHS_S = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const yrs = ['2024','2025','2026'];
  const selYear = yearFilter === 'ALL' ? '2026' : String(yearFilter);

  // Build actuals from data
  const actuals = {};
  MONTHS_L.forEach(m => {
    const rows = records.filter(r => String(r.year) === selYear && r.month === m && r.gross > 0);
    actuals[m] = {
      gross:   rows.reduce((a,r) => a + r.gross_total, 0),
      net:     rows.reduce((a,r) => a + r.net_total,   0),
      covers:  rows.reduce((a,r) => a + r.ppl_rest_total, 0),
      disc:    rows.reduce((a,r) => a + r.discounts_amt + r.complimentary_amt, 0),
    };
  });

  const bk = selYear;
  const bud = budgets[bk] || {};

  // Totals
  const totActGross  = MONTHS_L.reduce((a,m) => a + actuals[m].gross,  0);
  const totActNet    = MONTHS_L.reduce((a,m) => a + actuals[m].net,    0);
  const totActCovers = MONTHS_L.reduce((a,m) => a + actuals[m].covers, 0);
  const totBudGross  = MONTHS_L.reduce((a,m) => a + (bud[m]?.gross  || 0), 0);
  const totBudNet    = MONTHS_L.reduce((a,m) => a + (bud[m]?.net    || 0), 0);
  const totBudCovers = MONTHS_L.reduce((a,m) => a + (bud[m]?.covers || 0), 0);

  function pctClass(act, bud) {
    if (!bud) return '';
    const p = (act/bud - 1) * 100;
    return p >= 5 ? 'color:#00d4aa;font-weight:700' : p >= -5 ? 'color:#f5c842' : 'color:#ff4466;font-weight:700';
  }
  function pctStr(act, bud) {
    if (!bud) return '—';
    const p = (act/bud - 1) * 100;
    return (p >= 0 ? '+' : '') + p.toFixed(1) + '%';
  }
  function badge(act, bud) {
    if (!bud) return '—';
    const p = (act/bud - 1) * 100;
    const bg = p >= 5 ? '#00d4aa22' : p >= -5 ? '#f5c84222' : '#ff446622';
    const col = p >= 5 ? '#00d4aa' : p >= -5 ? '#f5c842' : '#ff4466';
    const icon = p >= 5 ? '▲' : p >= -5 ? '●' : '▼';
    return `<span style="background:${bg};color:${col};border-radius:4px;padding:2px 6px;font-size:11px;font-weight:700">${icon} ${pctStr(act,bud)}</span>`;
  }

  $('budget-content').innerHTML = `
    <!-- Year selector + KPI summary -->
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:16px;flex-wrap:wrap">
      <div style="font-family:monospace;font-size:11px;color:#555;text-transform:uppercase">Year:</div>
      ${yrs.map(y => `<button onclick="setBudgetYear('${y}',this)" class="pill-btn ${selYear===y?'on':''}">${y}</button>`).join('')}
      <div style="flex:1"></div>
      <button onclick="openBudgetEditor('${selYear}')" style="background:#ff6b35;color:#fff;border:none;border-radius:8px;padding:8px 16px;cursor:pointer;font-weight:700;font-size:12px">✏️ Set Budgets</button>
    </div>

    <!-- KPI summary cards -->
    <div class="grid4" style="margin-bottom:16px">
      ${kpiHtml('Actual Net', fmt(totActNet), '#00d4aa', totBudNet ? badge(totActNet, totBudNet)+' vs budget' : 'No budget set')}
      ${kpiHtml('Budget Net', totBudNet ? fmt(totBudNet) : 'Not set', '#f5c842', 'annual target')}
      ${kpiHtml('Actual Covers', fmtN(totActCovers), '#7c5cfc', totBudCovers ? badge(totActCovers, totBudCovers)+' vs budget' : 'No budget set')}
      ${kpiHtml('Budget Covers', totBudCovers ? fmtN(totBudCovers) : 'Not set', '#f5c842', 'annual target')}
    </div>

    <!-- Charts -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card">
        <div class="ct">Actual vs Budget — Net Revenue</div>
        <div style="position:relative;height:220px"><canvas id="ch-bud-net"></canvas></div>
      </div>
      <div class="card">
        <div class="ct">Actual vs Budget — Covers</div>
        <div style="position:relative;height:220px"><canvas id="ch-bud-cov"></canvas></div>
      </div>
    </div>

    <!-- Monthly detail table -->
    <div class="card">
      <div class="ct">Monthly Budget vs Actual Detail — ${selYear}</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>
            ${['Month','Budget Net','Actual Net','Variance','%','Budget Cov','Actual Cov','Var %','Budget Gross','Actual Gross','Var %'].map(h =>
              `<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`
            ).join('')}
          </tr></thead>
          <tbody>
            ${MONTHS_L.map(m => {
              const a = actuals[m];
              const b = bud[m] || {};
              const hasData = a.gross > 0 || b.gross;
              if (!hasData) return '';
              const netVar = (b.net||0) ? a.net - b.net : null;
              const covVar = (b.covers||0) ? a.covers - b.covers : null;
              const gVar   = (b.gross||0) ? a.gross - b.gross : null;
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                <td style="padding:7px 10px;font-weight:700">${m.slice(0,3)}</td>
                <td class="mono" style="padding:7px 10px;color:#f5c842">${b.net ? fmt(b.net) : '—'}</td>
                <td class="mono" style="padding:7px 10px;color:#00d4aa">${a.net ? fmt(a.net) : '—'}</td>
                <td class="mono" style="padding:7px 10px;${netVar !== null ? (netVar>=0?'color:#00d4aa':'color:#ff4466') : ''}">${netVar !== null ? (netVar>=0?'+':'')+fmt(netVar) : '—'}</td>
                <td style="padding:7px 10px">${b.net ? badge(a.net, b.net) : '—'}</td>
                <td class="mono" style="padding:7px 10px;color:#f5c842">${b.covers ? fmtN(b.covers) : '—'}</td>
                <td class="mono" style="padding:7px 10px;color:#7c5cfc">${a.covers ? fmtN(a.covers) : '—'}</td>
                <td style="padding:7px 10px">${b.covers ? badge(a.covers, b.covers) : '—'}</td>
                <td class="mono" style="padding:7px 10px;color:#f5c842">${b.gross ? fmt(b.gross) : '—'}</td>
                <td class="mono" style="padding:7px 10px;color:#ff6b35">${a.gross ? fmt(a.gross) : '—'}</td>
                <td style="padding:7px 10px">${b.gross ? badge(a.gross, b.gross) : '—'}</td>
              </tr>`;
            }).join('')}
            <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
              <td style="padding:7px 10px">TOTAL</td>
              <td class="mono" style="padding:7px 10px;color:#f5c842">${totBudNet ? fmt(totBudNet) : '—'}</td>
              <td class="mono" style="padding:7px 10px;color:#00d4aa">${fmt(totActNet)}</td>
              <td class="mono" style="padding:7px 10px;${totBudNet?(totActNet-totBudNet>=0?'color:#00d4aa':'color:#ff4466'):''}">
                ${totBudNet ? (totActNet-totBudNet>=0?'+':'')+fmt(totActNet-totBudNet) : '—'}</td>
              <td style="padding:7px 10px">${totBudNet ? badge(totActNet, totBudNet) : '—'}</td>
              <td class="mono" style="padding:7px 10px;color:#f5c842">${totBudCovers ? fmtN(totBudCovers) : '—'}</td>
              <td class="mono" style="padding:7px 10px;color:#7c5cfc">${fmtN(totActCovers)}</td>
              <td style="padding:7px 10px">${totBudCovers ? badge(totActCovers, totBudCovers) : '—'}</td>
              <td class="mono" style="padding:7px 10px;color:#f5c842">${totBudGross ? fmt(totBudGross) : '—'}</td>
              <td class="mono" style="padding:7px 10px;color:#ff6b35">${fmt(totActGross)}</td>
              <td style="padding:7px 10px">${totBudGross ? badge(totActGross, totBudGross) : '—'}</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- Budget Editor Modal -->
    <div id="budget-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.8);z-index:999;overflow-y:auto;padding:20px">
      <div style="max-width:700px;margin:0 auto;background:#1a1a2e;border-radius:16px;padding:24px;border:1px solid rgba(255,255,255,.1)">
        <h2 style="margin:0 0 20px;font-size:20px">Set Monthly Budgets — <span id="bud-yr-title"></span></h2>
        <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:8px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;padding:0 4px">
          <div>Month</div><div>Budget Gross</div><div>Budget Net</div><div>Budget Covers</div>
        </div>
        <div id="budget-editor-rows"></div>
        <div style="display:flex;gap:12px;margin-top:20px">
          <button onclick="saveBudgetEditor()" style="flex:1;background:#00d4aa;color:#000;border:none;border-radius:8px;padding:12px;font-weight:700;font-size:14px;cursor:pointer">💾 Save Budgets</button>
          <button onclick="$('budget-modal').style.display='none'" style="background:rgba(255,255,255,.1);color:#fff;border:none;border-radius:8px;padding:12px 24px;cursor:pointer">Cancel</button>
        </div>
      </div>
    </div>`;

  // Charts
  const labels = MONTHS_S;
  mkChart('ch-bud-net', {
    type:'bar',
    data:{ labels, datasets:[
      {label:'Budget', data: MONTHS_L.map(m => bud[m]?.net||null), backgroundColor:'rgba(245,200,66,.3)', borderColor:'#f5c842', borderWidth:2, borderRadius:4, type:'line', tension:.3, pointRadius:4},
      {label:'Actual', data: MONTHS_L.map(m => actuals[m].net||null), backgroundColor:'#00d4aa88', borderRadius:4, borderSkipped:false},
    ]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v/1000)+'k'}}}}
  });
  mkChart('ch-bud-cov', {
    type:'bar',
    data:{ labels, datasets:[
      {label:'Budget', data: MONTHS_L.map(m => bud[m]?.covers||null), backgroundColor:'rgba(245,200,66,.3)', borderColor:'#f5c842', borderWidth:2, borderRadius:4, type:'line', tension:.3, pointRadius:4},
      {label:'Actual', data: MONTHS_L.map(m => actuals[m].covers||null), backgroundColor:'#7c5cfc88', borderRadius:4, borderSkipped:false},
    ]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555'}}}}
  });
}

window.setBudgetYear = function(y, btn) {
  document.querySelectorAll('.pill-btn').forEach(b => b.classList.remove('on'));
  if(btn) btn.classList.add('on');
  // Re-render with new year (change global yearFilter temporarily)
  const prev = yearFilter;
  yearFilter = y;
  renderBudget();
  yearFilter = prev;
};

window.openBudgetEditor = function(yr) {
  const budgets = loadBudgets();
  const bud = budgets[yr] || {};
  const MONTHS_L = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  $('bud-yr-title').textContent = yr;
  $('budget-editor-rows').innerHTML = MONTHS_L.map(m => `
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:8px;align-items:center">
      <div style="font-weight:700;font-size:13px;padding:8px 4px">${m.slice(0,3)}</div>
      <input type="number" id="bed-g-${m}" value="${bud[m]?.gross||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
      <input type="number" id="bed-n-${m}" value="${bud[m]?.net||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
      <input type="number" id="bed-c-${m}" value="${bud[m]?.covers||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
    </div>`).join('');
  $('budget-modal').style.display = 'block';
};

window.saveBudgetEditor = function() {
  const yr = $('bud-yr-title').textContent;
  const MONTHS_L = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const budgets = loadBudgets();
  budgets[yr] = {};
  MONTHS_L.forEach(m => {
    const g = parseFloat($(`bed-g-${m}`)?.value||0)||0;
    const n = parseFloat($(`bed-n-${m}`)?.value||0)||0;
    const c = parseInt($(`bed-c-${m}`)?.value||0)||0;
    if(g||n||c) budgets[yr][m] = {gross:g, net:n, covers:c};
  });
  saveBudgets(budgets);
  $('budget-modal').style.display = 'none';
  renderBudget();
  toast('Budgets saved ✓','success');
};

// ═══════════════════════════════════════════════════════════════════
//  2. MENU ENGINEERING
// ═══════════════════════════════════════════════════════════════════

function renderMenuEngineering() {
  const allDishes = loadMenu();
  const dishes = menuCatFilter === 'ALL' ? allDishes : allDishes.filter(d=>d.category===menuCatFilter);

  // Pre-load Gladius menu if no dishes saved yet
  const existingDishes = loadMenu();
  if(existingDishes.length === 0 && GLADIUS_MENU && GLADIUS_MENU.length > 0) {
    saveMenu(GLADIUS_MENU.slice(0, 200)); // Load first 200 items with cost data
  }

  $('menu-content').innerHTML = `
    <!-- Add dish form -->
    <div class="card" style="margin-bottom:12px;border-top-color:#f5c842">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
        <div class="ct" style="margin:0">Menu Engineering Matrix — BCG Analysis</div>
        <div style="display:flex;gap:8px">
          <button onclick="loadGladiusMenu()" style="background:#7c5cfc;color:#fff;border:none;border-radius:8px;padding:7px 14px;cursor:pointer;font-weight:700;font-size:11px">🔄 Reload from Gladius (${GLADIUS_MENU.length} items)</button>
          <button onclick="clearMenu()" style="background:rgba(255,68,102,.2);color:#ff4466;border:1px solid #ff446633;border-radius:8px;padding:7px 14px;cursor:pointer;font-weight:700;font-size:11px">🗑 Clear All</button>
        </div>
      </div>
      <div style="display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr auto;gap:8px;margin-bottom:12px;align-items:end">
        <div>
          <div style="font-family:monospace;font-size:10px;color:#555;margin-bottom:4px;text-transform:uppercase">Dish Name</div>
          <input id="me-name" type="text" placeholder="e.g. Grilled Sea Bass" style="width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px;box-sizing:border-box">
        </div>
        <div>
          <div style="font-family:monospace;font-size:10px;color:#555;margin-bottom:4px;text-transform:uppercase">Category</div>
          <select id="me-cat" style="width:100%;background:#1a1a2e;border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
            <option>Starter</option><option>Main</option><option>Dessert</option><option>Beverage</option><option>Cocktail</option><option>Wine</option>
          </select>
        </div>
        <div>
          <div style="font-family:monospace;font-size:10px;color:#555;margin-bottom:4px;text-transform:uppercase">Sale Price (€)</div>
          <input id="me-price" type="number" placeholder="0.00" style="width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px;box-sizing:border-box">
        </div>
        <div>
          <div style="font-family:monospace;font-size:10px;color:#555;margin-bottom:4px;text-transform:uppercase">Food Cost (€)</div>
          <input id="me-cost" type="number" placeholder="0.00" style="width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px;box-sizing:border-box">
        </div>
        <div>
          <div style="font-family:monospace;font-size:10px;color:#555;margin-bottom:4px;text-transform:uppercase">Units Sold/Mo</div>
          <input id="me-units" type="number" placeholder="0" style="width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px;box-sizing:border-box">
        </div>
        <button onclick="addDish()" style="background:#ff6b35;color:#fff;border:none;border-radius:6px;padding:8px 16px;cursor:pointer;font-weight:700;white-space:nowrap;height:37px">+ Add</button>
      </div>
    </div>

    ${dishes.length === 0 ? `
      <div class="card" style="text-align:center;padding:40px;color:#444">
        <div style="font-size:48px;margin-bottom:12px">🍽</div>
        <div style="font-size:16px;font-weight:700;margin-bottom:8px">No dishes yet</div>
        <div style="font-size:13px">Add your menu items above to generate the engineering matrix</div>
      </div>` : `

    <!-- Matrix visualization -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card">
        <div class="ct">Menu Engineering Matrix (BCG)</div>
        <div id="me-matrix" style="position:relative;height:320px;background:rgba(255,255,255,.02);border-radius:8px;overflow:hidden"></div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:12px">
          ${[
            {label:'⭐ STARS',     col:'#00d4aa', desc:'High popularity · High margin → Promote'},
            {label:'🔧 PUZZLES',   col:'#7c5cfc', desc:'Low popularity · High margin → Reposition'},
            {label:'🐎 PLOWHORSES',col:'#f5c842', desc:'High popularity · Low margin → Reprice'},
            {label:'🐕 DOGS',      col:'#ff4466', desc:'Low popularity · Low margin → Remove/Review'},
          ].map(x => `<div style="background:rgba(255,255,255,.03);border-radius:6px;padding:8px;border-left:3px solid ${x.col}">
            <div style="font-weight:700;font-size:12px;color:${x.col}">${x.label}</div>
            <div style="font-size:10px;color:#555;margin-top:2px">${x.desc}</div>
          </div>`).join('')}
        </div>
      </div>
      <div class="card" style="border-top-color:#f5c842">
        <div class="ct">Contribution Margin by Category</div>
        <div style="position:relative;height:200px"><canvas id="ch-me-margin"></canvas></div>
        <div style="margin-top:12px">
          <div style="display:flex;justify-content:space-between;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;padding:0 4px;margin-bottom:6px">
            <span>SUMMARY</span><span>VALUE</span>
          </div>
          ${[
            {l:'Total Monthly Revenue', v: fmt(dishes.reduce((a,d)=>a+d.price*d.units,0))},
            {l:'Total Food Cost', v: fmt(dishes.reduce((a,d)=>a+d.cost*d.units,0))},
            {l:'Total Contribution Margin', v: fmt(dishes.reduce((a,d)=>a+(d.price-d.cost)*d.units,0))},
            {l:'Avg Food Cost %', v: (dishes.reduce((a,d)=>a+d.cost*d.units,0)/Math.max(1,dishes.reduce((a,d)=>a+d.price*d.units,0))*100).toFixed(1)+'%'},
          ].map(x => `<div style="display:flex;justify-content:space-between;padding:6px 4px;border-bottom:1px solid rgba(255,255,255,.04)">
            <span style="font-size:12px;color:#888">${x.l}</span>
            <span style="font-size:13px;font-weight:700;color:#00d4aa;font-family:monospace">${x.v}</span>
          </div>`).join('')}
        </div>
      </div>
    </div>

    <!-- Category filter -->
    <div class="card" style="margin-bottom:12px">
      <div class="ct">Filter by Category</div>
      <div style="display:flex;gap:6px;flex-wrap:wrap" id="menu-cat-filters">
        ${(()=>{
          const cats = [...new Set(loadMenu().map(d=>d.category))].sort();
          return ['ALL', ...cats].map(c =>
            `<button onclick="filterMenuCat('${c}',this)" class="pill-btn ${c==='ALL'?'on':''}" style="font-size:10px;padding:3px 10px">${c}</button>`
          ).join('');
        })()}
      </div>
    </div>

    <!-- Dish table -->
    <div class="card">
      <div class="ct">Dish Analysis Table</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>
            ${['Dish','Category','Price','Cost','Cost %','Margin','Units/Mo','Revenue','Classification','Action'].map(h =>
              `<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`
            ).join('')}
          </tr></thead>
          <tbody>
            ${(()=>{
              const avgMargin = dishes.reduce((a,d)=>a+(d.price-d.cost),0)/dishes.length;
              const avgUnits  = dishes.reduce((a,d)=>a+d.units,0)/dishes.length;
              return dishes.map((d,i) => {
                const margin = d.price - d.cost;
                const costPct = d.price ? (d.cost/d.price*100).toFixed(1) : '—';
                const rev = d.price * d.units;
                const isHighMargin = margin >= avgMargin;
                const isHighPop    = d.units >= avgUnits;
                let cls, clsColor, action;
                if(isHighMargin && isHighPop)    { cls='⭐ STAR';      clsColor='#00d4aa'; action='Promote & feature'; }
                else if(!isHighMargin && isHighPop){ cls='🐎 PLOWHORSE'; clsColor='#f5c842'; action='Increase price'; }
                else if(isHighMargin && !isHighPop){ cls='🔧 PUZZLE';    clsColor='#7c5cfc'; action='Better positioning'; }
                else                              { cls='🐕 DOG';       clsColor='#ff4466'; action='Review/Remove'; }
                return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                  <td style="padding:7px 10px;font-weight:700">${d.name}</td>
                  <td style="padding:7px 10px;font-size:11px;color:#888">${d.category}</td>
                  <td class="mono" style="padding:7px 10px;color:#ff6b35">€${d.price.toFixed(2)}</td>
                  <td class="mono" style="padding:7px 10px;color:#ff4466">€${d.cost.toFixed(2)}</td>
                  <td class="mono" style="padding:7px 10px;color:${parseFloat(costPct)<30?'#00d4aa':parseFloat(costPct)<35?'#f5c842':'#ff4466'}">${costPct}%</td>
                  <td class="mono" style="padding:7px 10px;color:#00d4aa">€${margin.toFixed(2)}</td>
                  <td class="mono" style="padding:7px 10px">${d.units}</td>
                  <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(rev)}</td>
                  <td style="padding:7px 10px"><span style="background:${clsColor}22;color:${clsColor};border-radius:4px;padding:2px 8px;font-size:11px;font-weight:700">${cls}</span></td>
                  <td style="padding:7px 10px;font-size:11px;color:#888">${action} <button onclick="removeDish(${i})" style="background:none;border:none;color:#ff446688;cursor:pointer;margin-left:8px">✕</button></td>
                </tr>`;
              }).join('');
            })()}
          </tbody>
        </table>
      </div>
    </div>`}`;

  // Draw matrix
  if(dishes.length > 0) {
    drawMenuMatrix(dishes);
    const avgMargin = dishes.reduce((a,d)=>a+(d.price-d.cost),0)/dishes.length;
    const byCategory = {};
    dishes.forEach(d => {
      if(!byCategory[d.category]) byCategory[d.category]={margin:0,count:0};
      byCategory[d.category].margin += (d.price-d.cost)*d.units;
      byCategory[d.category].count++;
    });
    const cats = Object.keys(byCategory);
    mkChart('ch-me-margin',{
      type:'bar',
      data:{labels:cats, datasets:[{
        label:'Contribution Margin (€)',
        data:cats.map(c=>byCategory[c].margin),
        backgroundColor:cats.map((_,i)=>['#00d4aa','#f5c842','#7c5cfc','#ff6b35','#ff4466','#ff9f43'][i%6]+'cc'),
        borderRadius:6, borderSkipped:false,
      }]},
      options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
        scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v/1000)+'k'}}}}
    });
  }
}



function renderPrimeCost() {
  const costs  = loadCosts();
  const seats  = loadSeats();
  const MONTHS_L = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTHS_S = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const selYear = yearFilter === 'ALL' ? '2026' : String(yearFilter);

  // Build monthly revenue from records
  const actuals = {};
  MONTHS_L.forEach(m => {
    const rows = records.filter(r => String(r.year) === selYear && r.month === m && r.gross > 0);
    actuals[m] = {
      gross: rows.reduce((a,r) => a + r.gross_total, 0),
      net:   rows.reduce((a,r) => a + r.net_total,   0),
      covers:rows.reduce((a,r) => a + r.ppl_rest_total, 0),
      days:  rows.length,
    };
  });

  const bk = selYear;
  const mc = costs[bk] || {};

  // KPIs
  const totNet   = MONTHS_L.reduce((a,m) => a + actuals[m].net, 0);
  const totFood  = MONTHS_L.reduce((a,m) => a + (mc[m]?.food_cost  || 0), 0);
  const totLabor = MONTHS_L.reduce((a,m) => a + (mc[m]?.labor_cost || 0), 0);
  const totBev   = MONTHS_L.reduce((a,m) => a + (mc[m]?.bev_cost   || 0), 0);
  const primeCost = totFood + totLabor;
  const foodPct   = totNet ? totFood/totNet*100 : 0;
  const laborPct  = totNet ? totLabor/totNet*100 : 0;
  const primePct  = totNet ? primeCost/totNet*100 : 0;
  const bevPct    = totNet ? totBev/totNet*100 : 0;

  function gauge(val, low, high, label, unit='%') {
    const pct = Math.min(100, val);
    const col = val <= low ? '#00d4aa' : val <= high ? '#f5c842' : '#ff4466';
    return `<div class="card" style="border-top-color:${col}">
      <div class="ct">${label}</div>
      <div style="font-size:28px;font-weight:900;color:${col};font-family:monospace">${val.toFixed(1)}${unit}</div>
      <div style="margin:8px 0;background:rgba(255,255,255,.06);border-radius:4px;height:6px;overflow:hidden">
        <div style="width:${Math.min(100,val)}%;height:100%;background:${col};border-radius:4px;transition:width .6s"></div>
      </div>
      <div style="font-size:10px;color:#555;font-family:monospace">
        ${val <= low ? '✅ On target' : val <= high ? '⚠️ Watch closely' : '🔴 Above target'}
        · Target: &lt;${high}%
      </div>
    </div>`;
  }

  $('prime-content').innerHTML = `
    <!-- Gauge KPIs -->
    <div class="grid4" style="margin-bottom:16px">
      ${gauge(foodPct,  28, 33,  'Food Cost %')}
      ${gauge(bevPct,   18, 25,  'Beverage Cost %')}
      ${gauge(laborPct, 25, 35,  'Labor Cost %')}
      ${gauge(primePct, 55, 65,  'Prime Cost %')}
    </div>

    <!-- RevPASH section -->
    <div class="card" style="margin-bottom:12px;border-top-color:#7c5cfc">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
        <div class="ct" style="margin:0">RevPASH — Revenue per Available Seat Hour</div>
        <div style="display:flex;align-items:center;gap:8px">
          <span style="font-family:monospace;font-size:11px;color:#555">Seats:</span>
          <input id="seats-input" type="number" value="${seats}" style="width:70px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:6px;font-size:13px;text-align:center">
          <span style="font-family:monospace;font-size:11px;color:#555">Op.Hours/Day:</span>
          <input id="ophours-input" type="number" value="${loadCosts()[bk]?.op_hours||12}" style="width:60px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:6px;font-size:13px;text-align:center">
          <button onclick="updateSeats()" style="background:#7c5cfc;color:#fff;border:none;border-radius:6px;padding:6px 12px;cursor:pointer;font-size:12px;font-weight:700">Update</button>
        </div>
      </div>
      <div class="grid4">
        ${MONTHS_L.filter(m => actuals[m].gross > 0).map(m => {
          const a = actuals[m];
          const opHours = mc.op_hours || 12;
          const revpash = a.days && seats ? a.gross / (seats * opHours * a.days) : 0;
          const col = revpash >= 25 ? '#00d4aa' : revpash >= 15 ? '#f5c842' : '#7c5cfc';
          return `<div style="background:rgba(255,255,255,.03);border-radius:8px;padding:12px;border-left:3px solid ${col}">
            <div style="font-size:11px;color:#555;font-family:monospace;text-transform:uppercase">${m.slice(0,3)} ${selYear}</div>
            <div style="font-size:22px;font-weight:900;color:${col};font-family:monospace;margin:4px 0">€${revpash.toFixed(2)}</div>
            <div style="font-size:10px;color:#666">${a.days}d · ${fmtN(a.covers)} covers · ${seats}×${opHours}h</div>
          </div>`;
        }).join('')}
      </div>
    </div>

    <!-- Cost input section -->
    <div class="card" style="margin-bottom:12px;border-top-color:#ff6b35">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
        <div class="ct" style="margin:0">Monthly Cost Entry — ${selYear}</div>
        <button onclick="openCostEditor('${selYear}')" style="background:#ff6b35;color:#fff;border:none;border-radius:8px;padding:8px 16px;cursor:pointer;font-weight:700;font-size:12px">✏️ Enter Costs</button>
      </div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>
            ${['Month','Net Rev','Food Cost','Food %','Bev Cost','Bev %','Labor Cost','Labor %','Prime Cost','Prime %'].map(h =>
              `<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`
            ).join('')}
          </tr></thead>
          <tbody>
            ${MONTHS_L.map(m => {
              const a = actuals[m]; const c = mc[m] || {};
              if(!a.gross && !c.food_cost) return '';
              const fP = a.net ? (c.food_cost||0)/a.net*100 : 0;
              const lP = a.net ? (c.labor_cost||0)/a.net*100 : 0;
              const bP = a.net ? (c.bev_cost||0)/a.net*100 : 0;
              const pP = a.net ? ((c.food_cost||0)+(c.labor_cost||0))/a.net*100 : 0;
              const col = v => v<=28?'#00d4aa':v<=35?'#f5c842':'#ff4466';
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                <td style="padding:7px 10px;font-weight:700">${m.slice(0,3)}</td>
                <td class="mono" style="padding:7px 10px;color:#00d4aa">${fmt(a.net)}</td>
                <td class="mono" style="padding:7px 10px">${c.food_cost?fmt(c.food_cost):'—'}</td>
                <td class="mono" style="padding:7px 10px;color:${col(fP)}">${fP?fP.toFixed(1)+'%':'—'}</td>
                <td class="mono" style="padding:7px 10px">${c.bev_cost?fmt(c.bev_cost):'—'}</td>
                <td class="mono" style="padding:7px 10px;color:${col(bP)}">${bP?bP.toFixed(1)+'%':'—'}</td>
                <td class="mono" style="padding:7px 10px">${c.labor_cost?fmt(c.labor_cost):'—'}</td>
                <td class="mono" style="padding:7px 10px;color:${col(lP)}">${lP?lP.toFixed(1)+'%':'—'}</td>
                <td class="mono" style="padding:7px 10px;font-weight:700">${(c.food_cost&&c.labor_cost)?fmt((c.food_cost||0)+(c.labor_cost||0)):'—'}</td>
                <td class="mono" style="padding:7px 10px;color:${pP?col(pP):'#555'};font-weight:700">${pP?pP.toFixed(1)+'%':'—'}</td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>
    </div>

    <!-- Cost Editor Modal -->
    <div id="cost-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.8);z-index:999;overflow-y:auto;padding:20px">
      <div style="max-width:720px;margin:0 auto;background:#1a1a2e;border-radius:16px;padding:24px;border:1px solid rgba(255,255,255,.1)">
        <h2 style="margin:0 0 20px;font-size:20px">Enter Monthly Costs — <span id="cost-yr-title"></span></h2>
        <div style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:8px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;padding:0 4px">
          <div>Month</div><div>Food Cost (€)</div><div>Bev Cost (€)</div><div>Labor Cost (€)</div><div>Op Hours/Day</div>
        </div>
        <div id="cost-editor-rows"></div>
        <div style="display:flex;gap:12px;margin-top:20px">
          <button onclick="saveCostEditor()" style="flex:1;background:#00d4aa;color:#000;border:none;border-radius:8px;padding:12px;font-weight:700;font-size:14px;cursor:pointer">💾 Save Costs</button>
          <button onclick="$('cost-modal').style.display='none'" style="background:rgba(255,255,255,.1);color:#fff;border:none;border-radius:8px;padding:12px 24px;cursor:pointer">Cancel</button>
        </div>
      </div>
    </div>`;
}

window.updateSeats = function() {
  const n = parseInt($('seats-input')?.value||80);
  const h = parseInt($('ophours-input')?.value||12);
  saveSeats(n);
  const selYear = yearFilter === 'ALL' ? '2026' : String(yearFilter);
  const costs = loadCosts(); costs[selYear] = costs[selYear]||{};
  costs[selYear].op_hours = h; saveCosts(costs);
  renderPrimeCost(); toast('Settings saved','success');
};

window.openCostEditor = function(yr) {
  const costs = loadCosts(); const mc = costs[yr]||{};
  const MONTHS_L=['January','February','March','April','May','June','July','August','September','October','November','December'];
  $('cost-yr-title').textContent=yr;
  $('cost-editor-rows').innerHTML=MONTHS_L.map(m=>`
    <div style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:8px;align-items:center">
      <div style="font-weight:700;font-size:13px;padding:8px 4px">${m.slice(0,3)}</div>
      <input type="number" id="ced-f-${m}" value="${mc[m]?.food_cost||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
      <input type="number" id="ced-b-${m}" value="${mc[m]?.bev_cost||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
      <input type="number" id="ced-l-${m}" value="${mc[m]?.labor_cost||''}" placeholder="0" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
      <input type="number" id="ced-h-${m}" value="${mc[m]?.op_hours||mc.op_hours||12}" placeholder="12" style="background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);color:#fff;border-radius:6px;padding:8px;font-size:13px">
    </div>`).join('');
  $('cost-modal').style.display='block';
};

window.saveCostEditor = function() {
  const yr=$('cost-yr-title').textContent;
  const MONTHS_L=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const costs=loadCosts(); costs[yr]=costs[yr]||{};
  MONTHS_L.forEach(m=>{
    const f=parseFloat($(`ced-f-${m}`)?.value||0)||0;
    const b=parseFloat($(`ced-b-${m}`)?.value||0)||0;
    const l=parseFloat($(`ced-l-${m}`)?.value||0)||0;
    const h=parseInt($(`ced-h-${m}`)?.value||12)||12;
    if(f||b||l) costs[yr][m]={food_cost:f,bev_cost:b,labor_cost:l,op_hours:h};
  });
  saveCosts(costs);
  $('cost-modal').style.display='none';
  renderPrimeCost(); toast('Costs saved ✓','success');
};

