function autoDetectColumns(headers) {
  const map = {};
  const rules = [
    { key:'dateCol',      patterns:['date','fecha','datum','data','ημερομηνία'] },
    { key:'totalGross',   patterns:['gross total','total gross','gross revenue','bruto','total sales'] },
    { key:'totalNet',     patterns:['net total','total net','net revenue','netto'] },
    { key:'coversTotal',  patterns:['covers','guests','pax','πελάτες','total covers','guests total'] },
    { key:'bfGross',      patterns:['breakfast gross','gross breakfast','bfast gross','πρωινό'] },
    { key:'lunchGross',   patterns:['lunch gross','gross lunch','μεσημέρι'] },
    { key:'afGross',      patterns:['afternoon gross','gross afternoon','απόγευμα'] },
    { key:'dnGross',      patterns:['dinner gross','gross dinner','δείπνο'] },
    { key:'barGross',     patterns:['bar gross','gross bar','μπαρ'] },
    { key:'discAmt',      patterns:['discount','discount amount','εκπτώσεις','desc'] },
    { key:'compAmt',      patterns:['comp','complimentary','κομπλιμέ'] },
  ];
  headers.forEach((h, i) => {
    const hl = String(h||'').toLowerCase().trim();
    rules.forEach(rule => {
      if (!map[rule.key] && rule.patterns.some(p => hl.includes(p))) {
        map[rule.key] = i;
      }
    });
  });
  return map;
}

// ── Parse a single row into a record ─────────────────────────────
function parseRow(row, colMap) {
  const get = (key) => {
    const idx = colMap[key];
    if (idx === undefined) return 0;
    const v = row[idx];
    const n = parseFloat(String(v||0).replace(/[€,]/g,''));
    return isNaN(n) ? 0 : Math.round(n * 100) / 100;
  };
  const getStr = (key) => {
    const idx = colMap[key];
    return idx !== undefined ? String(row[idx]||'').trim() : '';
  };

  // Parse date
  let ds = '';
  const rawDate = row[colMap.dateCol !== undefined ? colMap.dateCol : 0];
  if (rawDate instanceof Date) {
    ds = rawDate.toISOString().slice(0,10);
  } else if (typeof rawDate === 'number') {
    // Excel serial date
    const d = new Date(Math.round((rawDate - 25569) * 86400 * 1000));
    ds = d.toISOString().slice(0,10);
  } else {
    // String date - try multiple formats
    const s = String(rawDate||'').trim();
    const formats = [
      /^(\d{4})-(\d{2})-(\d{2})/, // 2024-01-15
      /^(\d{2})\/(\d{2})\/(\d{4})/, // 15/01/2024
      /^(\d{2})-(\d{2})-(\d{4})/, // 15-01-2024
      /^(\d{1,2})\/(\d{1,2})\/(\d{2,4})/, // 1/15/24
    ];
    for (const fmt of formats) {
      const m = s.match(fmt);
      if (m) {
        let [,a,b,c] = m;
        if (c.length === 2) c = '20' + c;
        if (parseInt(a) > 31) ds = `${a}-${b.padStart(2,'0')}-${c.padStart(2,'0')}`;
        else if (parseInt(c) > 2000) ds = `${c}-${b.padStart(2,'0')}-${a.padStart(2,'0')}`;
        break;
      }
    }
  }
  if (!ds || ds === 'NaN-NaN-NaN') return null;

  const year = parseInt(ds.slice(0,4));
  if (year < 2020 || year > 2030) return null;

  const tG = get('totalGross');
  const tN = get('totalNet') || Math.round(tG * 0.86 * 100) / 100;
  if (tG === 0) return null;

  const MONTHS_ALL = ['JANUARY','FEBRUARY','MARCH','APRIL','MAY','JUNE','JULY','AUGUST','SEPTEMBER','OCTOBER','NOVEMBER','DECEMBER'];
  const DOW = ['MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY','SUNDAY'];
  const d   = new Date(ds + 'T12:00:00');
  const month = MONTHS_ALL[d.getMonth()];
  const dayIdx = d.getDay();
  const day = DOW[dayIdx === 0 ? 6 : dayIdx - 1];

  const bfG = get('bfGross');  const bfN = get('bfNet')  || Math.round(bfG*.86*100)/100;
  const luG = get('lunchGross'); const luN = get('lunchNet') || Math.round(luG*.86*100)/100;
  const afG = get('afGross');  const afN = get('afNet')  || Math.round(afG*.86*100)/100;
  const dnG = get('dnGross');  const dnN = get('dnNet')  || Math.round(dnG*.86*100)/100;
  const brG = get('barGross'); const brN = get('barNet') || Math.round(brG*.86*100)/100;
  const cov = get('coversTotal');
  const discAmt = get('discAmt');
  const compAmt = get('compAmt');

  return {
    year, month, date: ds, day,
    gross: tG, net: tN, gross_total: tG, net_total: tN,
    rest_gross: tG, rest_net: tN,
    bfast_gross: bfG, bfast_net: bfN,
    lunch_gross: luG, lunch_net: luN,
    afternoon_gross: afG, afternoon_net: afN,
    dinner_gross: dnG, dinner_net: dnN,
    bar_gross: brG, bar_net: brN,
    event_lunch_gross: 0, event_lunch_net: 0,
    event_afternoon_gross: 0, event_afternoon_net: 0,
    event_dinner_gross: 0, event_dinner_net: 0,
    bar_event_gross: 0, bar_event_net: 0,
    ppl_rest_total: cov, ppl_total: cov,
    ppl_bfast: get('coversBfast'), ppl_lunch: get('coversLunch'),
    ppl_afternoon: get('coversAfternoon'), ppl_dinner: get('coversDinner'),
    ppl_bar: get('coversBar'), ppl_event: 0, ppl_avg: 0,
    avg_bfast:0, avg_lunch:0, avg_afternoon:0, avg_event:0, avg_dinner:0, avg_bar:0,
    avg_total: cov ? +(tN/cov).toFixed(2) : 0,
    discounts_amt: discAmt, discounts_pct: tG ? +(discAmt/tG).toFixed(4) : 0,
    complimentary_amt: compAmt, complimentary_pct: tG ? +(compAmt/tG).toFixed(4) : 0,
    staff_cost_total: 0, op_exp_total: 0,
    profit_loss_amt: 0, profit_loss_pct: 0,
    notes: '', source: 'pos_import',
  };
}

// ── Main import function ──────────────────────────────────────────
window.openPosImport = function() {
  $('pos-import-modal').style.display = 'block';
  $('pos-import-result').innerHTML = '';
  $('pos-file-input').value = '';
};

window.closePosImport = function() {
  $('pos-import-modal').style.display = 'none';
};

window.handlePosFile = function(evt) {
  const file = evt.target.files[0];
  if (!file) return;
  $('pos-import-result').innerHTML = `<div style="color:#f5c842;font-family:monospace;font-size:12px;padding:12px">📂 Reading ${file.name}...</div>`;

  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const data = new Uint8Array(e.target.result);
      const wb = XLSX.read(data, { type:'array', cellDates:true });
      const sheetName = wb.SheetNames[0];
      const ws = wb.Sheets[sheetName];
      const rows = XLSX.utils.sheet_to_json(ws, { header:1, defval:null });

      if (rows.length < 2) {
        $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ File appears empty or invalid</div>`;
        return;
      }

      const posType = $('pos-type-select').value;
      let colMap;

      if (posType === 'ri_template') {
        // Re-read with cellDates:false so dates are serial numbers (unambiguous)
        const wb2 = XLSX.read(data, { type:'array', cellDates:false });
        const ws2 = wb2.Sheets[wb2.SheetNames[0]];
        const rows2 = XLSX.utils.sheet_to_json(ws2, { header:1, defval:null, raw:true });
        const parsed = [];
        for (let i = 1; i < rows2.length; i++) {
          const r = parseRITemplateRow(rows2[i]);
          if (r) parsed.push(r);
        }
        if (!parsed.length) {
          $('pos-import-result').innerHTML = '<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ No valid rows found. Make sure Date column has valid dates and Gross Total > 0.</div>';
          return;
        }
        finalizePosImport(parsed, file.name, {});
        return;
      } else if (posType === 'auto') {
        // Auto-detect from headers
        const headerRow = rows[0].map(h => String(h||''));
        colMap = autoDetectColumns(headerRow);
        if (!colMap.dateCol && colMap.dateCol !== 0) colMap.dateCol = 0;
        if (!colMap.totalGross) {
          $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ Could not auto-detect columns. Please select your POS system or use the template.</div>`;
          return;
        }
      } else if (posType === 'geco') {
        // Use Geco template - skip header rows
        colMap = { ...POS_TEMPLATES.geco };
        const parsed = [];
        for (let i = POS_TEMPLATES.geco.dataStartRow; i < rows.length; i++) {
          const r = parseRow(rows[i], colMap);
          if (r) parsed.push(r);
        }
        finalizePosImport(parsed, file.name, colMap);
        return;
      } else {
        colMap = { ...POS_TEMPLATES[posType] };
      }

      const startRow = colMap.headerRow !== undefined ? colMap.headerRow + 1 : 1;
      const parsed = [];
      for (let i = startRow; i < rows.length; i++) {
        const r = parseRow(rows[i], colMap);
        if (r) parsed.push(r);
      }
      finalizePosImport(parsed, file.name, colMap);
    } catch(err) {
      $('pos-import-result').innerHTML = `<div style="color:#ff4466;font-family:monospace;font-size:12px;padding:12px">❌ Error reading file: ${err.message}</div>`;
    }
  };
  reader.readAsArrayBuffer(file);
};


window.confirmPosImport = function(mode) {
  const parsed = window._posImportPending;
  if (!parsed) return;

  if (mode === 'replace') {
    records = parsed;
  } else {
    // Merge: add records for dates not already in records
    const existingDates = new Set(records.map(r => r.date));
    const newRecords = parsed.filter(r => !existingDates.has(r.date));
    records = [...records, ...newRecords].sort((a,b) => a.date.localeCompare(b.date));
    toast(`Merged: ${newRecords.length} new days added`, 'success');
  }

  saveRecords();
  setSyncStatus(`POS Import: ${records.length} records`);
  closePosImport();
  renderPage(currentTab);
  toast(`✅ Import complete: ${parsed.length} days loaded`, 'success');
  window._posImportPending = null;
};

// ── Download Excel Template ───────────────────────────────────────
window.downloadPosTemplate = function() {
  const wb = XLSX.utils.book_new();
  const headers = [
    'Date','Day',
    'Gross Breakfast','Net Breakfast',
    'Gross Lunch','Net Lunch',
    'Gross Afternoon','Net Afternoon',
    'Gross Dinner','Net Dinner',
    'Gross Bar','Net Bar',
    'Gross Total','Net Total',
    'Covers Breakfast','Covers Lunch','Covers Afternoon','Covers Dinner','Covers Bar','Covers Total',
    'Discounts Amount','Complimentary Amount',
    'Notes'
  ];
  const example = [
    '2024-01-01','Monday',
    56.50,49.99,
    3081.10,2686.63,
    1976.00,1681.32,
    3688.50,3124.34,
    0,0,
    8802.10,7542.28,
    10,123,59,131,0,323,
    8.90,31.00,
    'New Year'
  ];
  const ws = XLSX.utils.aoa_to_sheet([headers, example]);
  ws['!cols'] = headers.map(() => ({wch:18}));
  XLSX.utils.book_append_sheet(wb, ws, 'Daily Sales');
  XLSX.writeFile(wb, 'restaurant-intelligence-import-template.xlsx');
  toast('Template downloaded ✓','success');
};


window.loadGladiusMenu = function() {
  if(!GLADIUS_MENU || !GLADIUS_MENU.length) { toast('No Gladius menu data found','error'); return; }
  saveMenu(GLADIUS_MENU);
  renderMenuEngineering();
  toast(`✅ Loaded ${GLADIUS_MENU.length} items from Gladius POS`,'success');
};

window.clearMenu = function() {
  if(!confirm('Clear all menu items?')) return;
  saveMenu([]);
  renderMenuEngineering();
};

let menuCatFilter = 'ALL';
window.filterMenuCat = function(cat, btn) {
  menuCatFilter = cat;
  document.querySelectorAll('#menu-cat-filters .pill-btn').forEach(b=>b.classList.remove('on'));
  if(btn) btn.classList.add('on');
  renderMenuEngineering();
};

